	internal class TCPCmdHandler
	{
		public static int GetHandlingCmdCount()
		{
			int count;
			lock (TCPCmdHandler.HandlingCmdDict)
			{
				count = TCPCmdHandler.HandlingCmdDict.Count;
			}
			return count;
		}

		public static void ProcessCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count)
		{
			TCPOutPacket tcpoutPacket = null;
			TCPProcessCmdResults tcpprocessCmdResults = TCPCmdHandler.ProcessCmd(tcpMgr, socket, tcpClientPool, tcpRandKey, pool, nID, data, count, out tcpoutPacket);
			if (tcpprocessCmdResults == TCPProcessCmdResults.RESULT_DATA && null != tcpoutPacket)
			{
				tcpMgr.MySocketListener.SendData(socket, tcpoutPacket, true);
			}
			else if (tcpprocessCmdResults == TCPProcessCmdResults.RESULT_FAILED)
			{
				if (nID != 22)
				{
					LogManager.WriteLog(2, string.Format("解析并执行命令失败: {0},{1}, 关闭连接", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				}
				tcpMgr.MySocketListener.CloseSocket(socket, "");
			}
		}

