					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Recv={1}", (TCPGameServerCmds)nID, text), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				string text2 = array[0];
				int num = Convert.ToInt32(array[1]);
				if (num < 0 || (!GameManager.TestGamePerformanceMode && text2 != GameManager.OnlineUserSession.FindUserID(socket)))
				{
					LogManager.WriteLog(2, string.Format("外挂登录，没有SocketSession的情况下，进行了登录, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (socket.IsKuaFuLogin)
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				SecPwdState secPwdState = SecondPasswordManager.GetSecPwdState(text2);
				if (secPwdState != null && secPwdState.NeedVerify)
				{
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, "-20", nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (MarryLogic.IsMarried(num))
				{
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, "-21", nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				TCPProcessCmdResults result = Global.TransferRequestToDBServer(tcpMgr, socket, tcpClientPool, tcpRandKey, pool, nID, data, count, out tcpOutPacket, socket.ServerId);
				if (null != tcpOutPacket)
				{
					string text3 = null;
					tcpOutPacket.GetPacketCmdData(out text3);
					if (null != text3)
					{
						string[] array2 = text3.Split(new char[]
						{
							':'
						});
						int num2 = Convert.ToInt32(array2[0]);
						if (num2 == num)
						{
							LiXianBaiTanManager.RemoveLiXianSaleGoodsItems(num);
							string ip = Global.GetSocketRemoteEndPoint(socket, false).Replace(":", ".");
							int zoneID = Convert.ToInt32(array2[1]);
							EventLogManager.AddRemoveRoleEvent(text2, zoneID, num, ip);
						}
					}
				}
				return result;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

		private static TCPProcessCmdResults ProcessInitGameCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
