				}
				string text3 = "";
				if (array.Length >= 3)
				{
					text3 = array[2];
				}
				int num2 = 0;
				if (array.Length >= 4)
				{
					num2 = ((Convert.ToInt32(array[3]) == 1) ? 1 : 0);
