		private static TCPProcessCmdResults ProcessSpriteMoveCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			SpriteMoveData spriteMoveData = null;
			try
			{
				spriteMoveData = DataHelper.BytesToObject2<SpriteMoveData>(data, 0, count, socket.m_Socket);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				SingletonTemplate<ProtoChecker>.Instance().Check<SpriteMoveData>(data, 0, count, socket.m_Socket);
				if (null == spriteMoveData)
				{
					LogManager.WriteLog(2, string.Format("指令解析错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int roleID = spriteMoveData.roleID;
				int mapCode = spriteMoveData.mapCode;
				int action = spriteMoveData.action;
				int toX = spriteMoveData.toX;
				int toY = spriteMoveData.toY;
				int extAction = spriteMoveData.extAction;
				int fromX = spriteMoveData.fromX;
				int fromY = spriteMoveData.fromY;
				long startMoveTicks = spriteMoveData.startMoveTicks;
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref roleID))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), roleID), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				if (mapCode != gameClient.ClientData.MapCode)
				{
					gameClient.CheckCheatData.MismatchingMapCode = true;
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (gameClient.ClientData.WaitingForChangeMap)
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (GameManager.FlagCheckCmdPosition > 0)
				{
					GameMap gameMap = GameManager.MapMgr.GetGameMap(mapCode);
					if (null == gameMap)
					{
						return TCPProcessCmdResults.RESULT_OK;
					}
					if (-1 != toX && -1 != toY && !Global.IsGridReachable(mapCode, toX / gameMap.MapGridWidth, toY / gameMap.MapGridHeight))
					{
						return TCPProcessCmdResults.RESULT_OK;
					}
				}
				if (gameClient.ClientData.DSHideStart > 0L)
				{
					Global.RemoveBufferData(gameClient, 41);
					gameClient.ClientData.DSHideStart = 0L;
					GameManager.ClientMgr.NotifyDSHideCmd(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, gameClient);
				}
				Global.EndMeditate(gameClient);
				CaiJiLogic.CancelCaiJiState(gameClient);
				gameClient.ClientData.MoveAndActionNum++;
				string pathString = spriteMoveData.pathString;
				if (Data.IgnoreClientPos)
				{
					GameManager.ClientMgr.StopClientStoryboard(gameClient, spriteMoveData.startMoveTicks, -1, -1);
				}
				else
				{
					GameManager.ClientMgr.StopClientStoryboard(gameClient, -1);
				}
				gameClient.ClientData.RolePathString = pathString;
				gameClient.ClientData.RoleStartMoveTicks = startMoveTicks;
				if (gameClient.RoleMagicHelper.GetFreeze())
				{
					ClientCmdCheck.ClientStopMove(gameClient, fromX, fromY, startMoveTicks);
					return TCPProcessCmdResults.RESULT_OK;
				}
				double num = RoleAlgorithm.GetMoveSpeed(gameClient);
				if (gameClient.ClientData.HorseDbID > 0)
				{
					double horseSpeed = Global.GetHorseSpeed(gameClient);
					num += horseSpeed;
				}
				gameClient.ClientData.CurrentAction = action;
				gameClient.ClientData.MoveSpeed = num;
				string pathStr = DataHelper.UnZipStringToBase64(pathString);
				if (!ClientCmdCheck.ValidateClientMoveStartTicks(gameClient, startMoveTicks))
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				if ((double)(TimeUtil.NOW() - gameClient.ClientData.InstantMoveTick) < 500.0)
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				List<Point> path = Global.TransStringToPathArr(pathStr);
				bool stepMove;
				if (!ClientCmdCheck.SpriteMoveCmd(gameClient, fromX, fromY, toX, toY, startMoveTicks, num, path, out stepMove))
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (!GameManager.ClientMgr.StartClientStoryboard(gameClient, startMoveTicks, path, stepMove))
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				SpriteNotifyOtherMoveData spriteNotifyOtherMoveData = new SpriteNotifyOtherMoveData();
				spriteNotifyOtherMoveData.roleID = gameClient.ClientData.RoleID;
				spriteNotifyOtherMoveData.moveCost = num;
				spriteNotifyOtherMoveData.mapCode = mapCode;
				gameClient.sendCmd<SpriteNotifyOtherMoveData>(nID, spriteNotifyOtherMoveData, false);
				spriteNotifyOtherMoveData.action = action;
				spriteNotifyOtherMoveData.toX = toX;
				spriteNotifyOtherMoveData.toY = toY;
				spriteNotifyOtherMoveData.extAction = extAction;
				spriteNotifyOtherMoveData.fromX = fromX;
				spriteNotifyOtherMoveData.fromY = fromY;
				spriteNotifyOtherMoveData.startMoveTicks = startMoveTicks;
				spriteNotifyOtherMoveData.pathString = gameClient.ClientData.RolePathString;
				GameManager.ClientMgr.NotifyOthersMyMoving(tcpMgr.MySocketListener, pool, spriteNotifyOtherMoveData, gameClient, nID, null);
				return TCPProcessCmdResults.RESULT_OK;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

		private static TCPProcessCmdResults ProcessSpriteMoveEndCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			SCMoveEnd scmoveEnd = null;
			try
			{
				SingletonTemplate<ProtoChecker>.Instance().Check<SCMoveEnd>(data, 0, count, socket.m_Socket);
				if (!CheckHelper.CheckTCPCmdHandle<SCMoveEnd>(socket, nID, data, count, out scmoveEnd))
				{
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int roleID = scmoveEnd.RoleID;
