		private static TCPProcessCmdResults ProcessSpriteAttackCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			SpriteAttackData spriteAttackData = null;
			try
			{
				spriteAttackData = DataHelper.BytesToObject<SpriteAttackData>(data, 0, count);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				if (null == spriteAttackData)
				{
					LogManager.WriteLog(2, string.Format("指令解析错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int roleID = spriteAttackData.roleID;
				int roleX = spriteAttackData.roleX;
				int roleY = spriteAttackData.roleY;
				int enemy = spriteAttackData.enemy;
				int enemyX = spriteAttackData.enemyX;
				int enemyY = spriteAttackData.enemyY;
				int realEnemyX = spriteAttackData.realEnemyX;
				int realEnemyY = spriteAttackData.realEnemyY;
				int num = spriteAttackData.magicCode;
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref roleID))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), roleID), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				if (gameClient.ClientData.CurrentLifeV <= 0)
				{
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (roleX - gameClient.ClientData.PosX > GameManager.MaxAttackDistance || roleX - gameClient.ClientData.PosX < -GameManager.MaxAttackDistance || roleY - gameClient.ClientData.PosY > GameManager.MaxAttackDistance || roleY - gameClient.ClientData.PosY < -GameManager.MaxAttackDistance)
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (gameClient.ClientData.IsDongJie())
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (!Global.CanMapUseMagic(gameClient, num))
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (num == -1 && GameManager.TestGamePerformanceMode)
				{
					EMagicSwordTowardType magicSwordTypeByWeapon = GameManager.MagicSwordMgr.GetMagicSwordTypeByWeapon(gameClient.ClientData.Occupation, gameClient.UsingEquipMgr.GetWeaponEquipList(), gameClient);
					int[] array = JingJiChangConstants.GetJingJiChangeSkillList(gameClient, Global.CalcOriginalOccupationID(gameClient.ClientData.Occupation), magicSwordTypeByWeapon);
					int randomNumber = Global.GetRandomNumber(0, array.Length);
					if (randomNumber == 0)
					{
						array = JingJiChangConstants.getJingJiChangeFiveCombatSkillList(Global.CalcOriginalOccupationID(gameClient.ClientData.Occupation), magicSwordTypeByWeapon);
						randomNumber = Global.GetRandomNumber(0, array.Length);
					}
					num = array[randomNumber];
				}
				Global.EndMeditate(gameClient);
				SystemXmlItem systemXmlItem = null;
				if (!GameManager.SystemMagicsMgr.SystemXmlItemDict.TryGetValue(num, out systemXmlItem))
				{
					LogManager.WriteLog(1, string.Format("拒绝技能释放#未找到技能静态数据,RoleID={0}({1}),MagicCode={2}", roleID, Global.FormatRoleName4(gameClient), num), null, true);
					return TCPProcessCmdResults.RESULT_OK;
				}
				int intValue = systemXmlItem.GetIntValue("ToOcuupation", -1);
				if (intValue != gameClient.ClientData.Occupation && intValue != 1000)
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (!BianShenManager.getInstance().CanUseMagic(gameClient, num))
				{
					LogManager.WriteLog(2, string.Format("玩家释放的技能和变身状态不匹配(外挂),RoleID={0}({1}),MagicCode={2}", roleID, Global.FormatRoleName4(gameClient), num), null, true);
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (!SpriteAttack.CanUseMaigc(gameClient, num))
				{
					if (socket.session.gmPriority > 0)
					{
						LogManager.WriteLog(1, string.Format("拒绝技能释放#玩家释放的技能和职业不匹配,RoleID={0}({1}),MagicCode={2}", roleID, Global.FormatRoleName4(gameClient), num), null, true);
					}
					return TCPProcessCmdResults.RESULT_OK;
				}
				int intValue2 = systemXmlItem.GetIntValue("UseType", -1);
				if (intValue2 == 1 && gameClient.ClientData.IsFlashPlayer != 0 && gameClient.ClientData.MapCode != 6090)
				{
					List<GoodsData> usingAttackWeaponGoods = Global.GetUsingAttackWeaponGoods(gameClient);
					if (usingAttackWeaponGoods == null || usingAttackWeaponGoods.Count<GoodsData>() < 0)
					{
						LogManager.WriteLog(1, string.Format("拒绝技能释放#该技能需要武器才能释放,RoleID={0}({1}),MagicCode={2}", roleID, Global.FormatRoleName4(gameClient), num), null, true);
						return TCPProcessCmdResults.RESULT_OK;
					}
				}
				if (intValue2 == 1)
				{
					int num2;
					if (!RebornEquip.IsWeaponCanAttackOrActtion(gameClient, out num2))
					{
						return TCPProcessCmdResults.RESULT_OK;
					}
				}
				gameClient.ClientData.MoveAndActionNum++;
				if (Data.IgnoreClientPos)
				{
					GameManager.ClientMgr.StopClientStoryboard(gameClient, spriteAttackData.clientTicks, -1, -1);
				}
				else
				{
					GameManager.ClientMgr.StopClientStoryboard(gameClient, -1);
				}
				ClientCmdCheck.ClientStopMove(gameClient, roleX, roleY, spriteAttackData.clientTicks);
				if (!Data.IgnoreClientPos)
				{
					gameClient.ClientData.PosX = roleX;
					gameClient.ClientData.PosY = roleY;
				}
				gameClient.ClientData.ReportPosTicks = 0L;
				if (!GameManager.MapGridMgr.DictGrids[gameClient.ClientData.MapCode].MoveObject(-1, -1, roleX, roleY, gameClient))
				{
					if (socket.session.gmPriority > 0)
					{
						LogManager.WriteLog(1, string.Format("拒绝技能释放#自身位置异常,RoleID={0}({1}),MagicCode={2}", roleID, Global.FormatRoleName4(gameClient), num), null, true);
					}
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (gameClient.ClientData.HideSelf > 0 || gameClient.ClientData.HideGM > 0 || !GameManager.MagicSwordMgr.CanUseMagicOfMagicSword(gameClient, num) || !EscapeBattleManager.getInstance().CanUseMaigc(gameClient))
				{
					if (socket.session.gmPriority > 0)
					{
						LogManager.WriteLog(1, string.Format("拒绝技能释放#不满足释放条件,RoleID={0}({1}),MagicCode={2}", roleID, Global.FormatRoleName4(gameClient), num), null, true);
					}
					return TCPProcessCmdResults.RESULT_OK;
				}
				CaiJiLogic.CancelCaiJiState(gameClient);
				ZuoQiManager.getInstance().RoleDisMount(gameClient, true);
				if (!gameClient.ClientData.MyMagicCoolDownMgr.SkillCoolDown(num))
				{
					if (socket.session.gmPriority > 0)
					{
						LogManager.WriteLog(2, string.Format("拒绝技能释放#CD未结束1,RoleID={0}({1}),MagicCode={2}", roleID, Global.FormatRoleName4(gameClient), num), null, true);
					}
					return TCPProcessCmdResults.RESULT_OK;
				}
				long num3 = TimeUtil.NOW();
				if (systemXmlItem.GetStringValue("HorseSkill") == "1")
				{
					ExtData clientExtData = ExtDataManager.GetClientExtData(gameClient);
					if (num3 < clientExtData.ZuoQiSkillCDTicks)
					{
						if (socket.session.gmPriority > 0)
						{
							LogManager.WriteLog(2, string.Format("拒绝技能释放#CD未结束1,RoleID={0}({1}),MagicCode={2}", roleID, Global.FormatRoleName4(gameClient), num), null, true);
						}
						return TCPProcessCmdResults.RESULT_OK;
					}
				}
				if (!SpriteAttack.IsMagicEnough(gameClient, num))
				{
					if (socket.session.gmPriority > 0)
					{
						LogManager.WriteLog(2, string.Format("拒绝技能释放#魔法值不足,RoleID={0}({1}),MagicCode={2}", roleID, Global.FormatRoleName4(gameClient), num), null, true);
					}
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (!SpriteAttack.IsParentActionDone(gameClient, num))
				{
					if (socket.session.gmPriority > 0)
					{
						LogManager.WriteLog(2, string.Format("拒绝技能释放#父技能未释放,RoleID={0}({1}),MagicCode={2}", roleID, Global.FormatRoleName4(gameClient), num), null, true);
					}
					return TCPProcessCmdResults.RESULT_OK;
				}
				SpriteActionData currentActionData = gameClient.ClientData.CurrentActionData;
				if (currentActionData != null)
				{
					gameClient.ClientData.CurrentActionData = null;
					GameManager.ClientMgr.NotifyOthersMyAction(tcpMgr.MySocketListener, pool, gameClient, currentActionData, 114);
				}
				gameClient.buffManager.SetStatusBuff(114, TimeUtil.NOW(), Data.FightStateTime, 0L);
				SpriteAttack.ProcessAttack(gameClient, enemy, enemyX, enemyY, realEnemyX, realEnemyY, num, -1, 1.0);
				return TCPProcessCmdResults.RESULT_OK;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

		private static TCPProcessCmdResults ProcessSpriteMagicCodeCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			SpriteMagicCodeData spriteMagicCodeData = null;
			try
			{
				spriteMagicCodeData = DataHelper.BytesToObject2<SpriteMagicCodeData>(data, 0, count, socket.m_Socket);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				SingletonTemplate<ProtoChecker>.Instance().Check<SpriteMagicCodeData>(data, 0, count, socket.m_Socket);
				if (null == spriteMagicCodeData)
				{
					LogManager.WriteLog(2, string.Format("指令解析错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int roleID = spriteMagicCodeData.roleID;
				int mapCode = spriteMagicCodeData.mapCode;
				int num = spriteMagicCodeData.magicCode;
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref roleID))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), roleID), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				if (num == -1 && GameManager.TestGamePerformanceMode)
				{
					EMagicSwordTowardType magicSwordTypeByWeapon = GameManager.MagicSwordMgr.GetMagicSwordTypeByWeapon(gameClient.ClientData.Occupation, gameClient.UsingEquipMgr.GetWeaponEquipList(), gameClient);
					int[] jingJiChangeSkillList = JingJiChangConstants.GetJingJiChangeSkillList(gameClient, Global.CalcOriginalOccupationID(gameClient.ClientData.Occupation), magicSwordTypeByWeapon);
					int randomNumber = Global.GetRandomNumber(0, jingJiChangeSkillList.Length);
					num = jingJiChangeSkillList[randomNumber];
				}
				if (mapCode != gameClient.ClientData.MapCode)
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (gameClient.ClientData.HideSelf > 0 || gameClient.ClientData.HideGM > 0 || !GameManager.MagicSwordMgr.CanUseMagicOfMagicSword(gameClient, num))
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (gameClient.ClientData.IsDongJie())
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (!gameClient.ClientData.MyMagicCoolDownMgr.SkillCoolDown(num))
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (!Global.CanMapUseMagic(gameClient, num))
				{
					num = -1;
				}
				if (!BianShenManager.getInstance().CanUseMagic(gameClient, num))
				{
					LogManager.WriteLog(2, string.Format("玩家释放的技能和变身状态不匹配(外挂),RoleID={0}({1}),MagicCode={2}", roleID, Global.FormatRoleName4(gameClient), num), null, true);
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (!SpriteAttack.CanUseMaigc(gameClient, num))
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				ZuoQiManager.getInstance().RoleDisMount(gameClient, true);
				gameClient.ClientData.CurrentMagicCode = num;
				gameClient.ClientData.CurrentMagicTicks = TimeUtil.NOW();
				double num2 = Math.Min(1.0, ShenShiManager.getInstance().GetMagicCodeSkillCDSubPercent(gameClient, num));
				if (num2 > 0.0)
				{
					gameClient.ClientData.CurrentMagicCDSubPercent = Math.Min(num2, 1.0);
					gameClient.sendCmd(1882, num + ":" + (1.0 - gameClient.ClientData.CurrentMagicCDSubPercent), false);
				}
				SpriteActionData currentActionData = gameClient.ClientData.CurrentActionData;
				if (currentActionData != null)
				{
					gameClient.ClientData.CurrentActionData = null;
					GameManager.ClientMgr.NotifyOthersMyAction(tcpMgr.MySocketListener, pool, gameClient, currentActionData, 114);
				}
				GameManager.ClientMgr.NotifyOthersMagicCode(tcpMgr.MySocketListener, pool, gameClient, roleID, mapCode, num, 116);
				tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data, 0, count, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

