		private static TCPProcessCmdResults ProcessSpriteClickOnCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			try
			{
				SingletonTemplate<ProtoChecker>.Instance().Check<CS_ClickOn>(data, 0, count, socket.m_Socket);
				CS_ClickOn cs_ClickOn = null;
				if (!CheckHelper.CheckTCPCmdHandle<CS_ClickOn>(socket, nID, data, count, out cs_ClickOn))
				{
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int roleId = cs_ClickOn.RoleId;
				int mapCode = cs_ClickOn.MapCode;
				int npcId = cs_ClickOn.NpcId;
				int extId = cs_ClickOn.ExtId;
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref roleId))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), roleId), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				if (gameClient.ClientData.HideGM > 0)
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				NPCData npcdata = new NPCData
				{
					MapCode = mapCode,
					RoleID = roleId,
					NPCID = npcId,
					ExtensionID = extId
				};
				SystemXmlItem systemXmlItem = null;
				if (!GameManager.SystemNPCsMgr.SystemXmlItemDict.TryGetValue(extId, out systemXmlItem))
				{
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				string stringValue = systemXmlItem.GetStringValue("GatherCondition");
				if (stringValue != null && "" != stringValue)
				{
					string[] array = stringValue.Split(new char[]
					{
						','
					});
					int num = Global.SafeConvertToInt32(array[0]);
					if (!ProcessTask.IfActivateTask(gameClient, num))
					{
						npcdata.GatherTime = -2;
						tcpOutPacket = DataHelper.ObjectToTCPOutPacket<NPCData>(npcdata, pool, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					if (0 == gameClient.ClientData.gatherNpcID)
					{
						gameClient.ClientData.gatherNpcID = extId;
						gameClient.ClientData.gatherTicks = TimeUtil.NOW() + 1500L;
						npcdata.GatherTime = 2;
						tcpOutPacket = DataHelper.ObjectToTCPOutPacket<NPCData>(npcdata, pool, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					if (extId == gameClient.ClientData.gatherNpcID)
					{
						if (TimeUtil.NOW() < gameClient.ClientData.gatherTicks)
						{
							gameClient.ClientData.gatherTicks = TimeUtil.NOW() + 1500L;
							npcdata.GatherTime = 2;
							tcpOutPacket = DataHelper.ObjectToTCPOutPacket<NPCData>(npcdata, pool, nID);
							return TCPProcessCmdResults.RESULT_DATA;
						}
						gameClient.ClientData.gatherNpcID = 0;
						ProcessTask.Process(tcpMgr.MySocketListener, pool, gameClient, npcId, extId, num, TaskTypes.GatherMonster, null, 0, -1L, null);
						npcdata.GatherTime = -1;
						tcpOutPacket = DataHelper.ObjectToTCPOutPacket<NPCData>(npcdata, pool, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
				}
				NPC npc = null;
				SceneUIClasses mapSceneType = Global.GetMapSceneType(mapCode);
				ProcessClickOnNpcEventObject processClickOnNpcEventObject = new ProcessClickOnNpcEventObject(gameClient, npc, npcId, extId);
				if (!GlobalEventSource4Scene.getInstance().fireEvent(processClickOnNpcEventObject, mapSceneType) && processClickOnNpcEventObject.Handled)
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (mapSceneType == 24)
				{
					if (LuoLanChengZhanManager.getInstance().OnSpriteClickOnNpc(gameClient, npcId, extId))
					{
						return TCPProcessCmdResults.RESULT_OK;
					}
				}
				GlobalNew.GetNpcTaskData(gameClient, extId, npcdata);
				GlobalNew.GetNpcFunctionData(gameClient, extId, npcdata, systemXmlItem);
				if (null != npcdata.OperationIDs)
				{
					if (npcdata.OperationIDs.Contains(60))
					{
						npc = NPCGeneralManager.FindNPC(mapCode, extId);
						if (null != npc)
						{
							if (npc.MapCode == gameClient.ClientData.MapCode)
							{
								if (Global.GetTwoPointDistanceSquare(npc.CurrentPos, gameClient.CurrentPos) < 810000.0)
								{
									gameClient.ClientData.OpenPortableBagPoint = gameClient.CurrentPos;
								}
							}
						}
					}
				}
				ProcessTask.Process(tcpMgr.MySocketListener, pool, gameClient, npcId, extId, -1, TaskTypes.Talk, null, 0, -1L, null);
				tcpOutPacket = DataHelper.ObjectToTCPOutPacket<NPCData>(npcdata, pool, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

		private static TCPProcessCmdResults ProcessSpriteNewTaskCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			string text = null;
			try
			{
				text = new UTF8Encoding().GetString(data, 0, count);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				string[] array = text.Split(new char[]
				{
					':'
				});
				if (array.Length != 3)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				int npcID = Convert.ToInt32(array[1]);
				int num2 = Convert.ToInt32(array[2]);
				GameClient client = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, client, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				TCPProcessCmdResults tcpprocessCmdResults = Global.TakeNewTask(tcpMgr, socket, tcpClientPool, tcpRandKey, pool, nID, client, num, num2, npcID, out tcpOutPacket);
				if (TCPProcessCmdResults.RESULT_OK == tcpprocessCmdResults)
				{
					if (105 == num2)
					{
						FreshPlayerCopySceneManager.AddShuiJingGuanCaiMonsters(client);
					}
				}
				return tcpprocessCmdResults;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

		private static TCPProcessCmdResults ProcessSpriteMapChangeCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			SCMapChange scmapChange = null;
			try
			{
				SingletonTemplate<ProtoChecker>.Instance().Check<SCMapChange>(data, 0, count, socket.m_Socket);
				if (!CheckHelper.CheckTCPCmdHandle<SCMapChange>(socket, nID, data, count, out scmapChange))
				{
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int roleID = scmapChange.RoleID;
				int teleportID = scmapChange.TeleportID;
				int num = scmapChange.NewMapCode;
				int num2 = scmapChange.ToNewMapX;
				int num3 = scmapChange.ToNewMapY;
				int toNewDiection = scmapChange.ToNewDiection;
				int state = scmapChange.State;
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref roleID))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), roleID), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num4 = state & 1;
				if (num4 != 0)
				{
					lock (gameClient.ClientData.MapCodeAlreadyList)
					{
						if (!gameClient.ClientData.MapCodeAlreadyList.Contains(num))
						{
							gameClient.ClientData.WaitingForChangeMap = false;
							gameClient.ClientData.WaitingNotifyChangeMap = false;
							return TCPProcessCmdResults.RESULT_OK;
						}
					}
				}
				if (gameClient.CheckCheatData.GmGotoShadowMapCode == num)
				{
