		private static TCPProcessCmdResults ProcessSpriteGoodsStallCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			string text = null;
			try
			{
				text = new UTF8Encoding().GetString(data, 0, count);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				string[] array = text.Split(new char[]
				{
					':'
				});
				if (array.Length != 4)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				if (gameClient.ClientSocket.IsKuaFuLogin)
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				int num2 = Convert.ToInt32(array[1]);
				int num3 = Convert.ToInt32(array[2]);
				string text2 = array[3];
				if (num2 == 1)
				{
					if (gameClient.ClientData.Level < 10)
					{
						GameManager.ClientMgr.NotifyGoodsStallCmd(tcpMgr.MySocketListener, pool, gameClient, -9, num2);
						return TCPProcessCmdResults.RESULT_OK;
					}
					if (!Global.AllowStartStall(gameClient))
					{
						GameManager.ClientMgr.NotifyGoodsStallCmd(tcpMgr.MySocketListener, pool, gameClient, -8, num2);
						return TCPProcessCmdResults.RESULT_OK;
					}
					if (gameClient.ClientData.StallDataItem != null)
					{
						GameManager.ClientMgr.NotifyGoodsStallCmd(tcpMgr.MySocketListener, pool, gameClient, -10, num2);
						return TCPProcessCmdResults.RESULT_OK;
					}
					StallData stallData = new StallData
					{
						StallID = 0,
						RoleID = gameClient.ClientData.RoleID,
						StallName = text2,
						StallMessage = "",
						GoodsList = new List<GoodsData>(),
						GoodsPriceDict = new Dictionary<int, int>(),
						AddDateTime = TimeUtil.NOW()
					};
					gameClient.ClientData.StallDataItem = stallData;
					GameManager.ClientMgr.NotifyGoodsStallData(tcpMgr.MySocketListener, pool, gameClient, stallData);
					GameManager.ClientMgr.NotifyGoodsStallCmd(tcpMgr.MySocketListener, pool, gameClient, 0, num2);
				}
				else if (num2 == 2)
				{
					if (gameClient.ClientData.StallDataItem == null)
					{
						GameManager.ClientMgr.NotifyGoodsStallCmd(tcpMgr.MySocketListener, pool, gameClient, -10, num2);
						return TCPProcessCmdResults.RESULT_OK;
					}
					lock (gameClient.ClientData.StallDataItem)
					{
						gameClient.ClientData.StallDataItem.Start = 1;
					}
					GameManager.ClientMgr.NotifyGoodsStallCmd(tcpMgr.MySocketListener, pool, gameClient, 0, num2);
					GameManager.ClientMgr.NotifySpriteStartStall(tcpMgr.MySocketListener, pool, gameClient);
					ChengJiuManager.OnFirstBaiTan(gameClient);
				}
				else if (num2 == 3)
				{
					if (gameClient.ClientData.StallDataItem == null)
					{
						GameManager.ClientMgr.NotifyGoodsStallCmd(tcpMgr.MySocketListener, pool, gameClient, -10, num2);
						return TCPProcessCmdResults.RESULT_OK;
					}
					bool flag2 = false;
					lock (gameClient.ClientData.StallDataItem)
					{
						flag2 = (gameClient.ClientData.StallDataItem.Start == 1);
						gameClient.ClientData.StallDataItem.StallName = "";
					}
					if (flag2)
					{
						GameManager.ClientMgr.NotifySpriteStartStall(tcpMgr.MySocketListener, pool, gameClient);
					}
					Global.RestoreStallData(gameClient, gameClient.ClientData.StallDataItem);
					gameClient.ClientData.StallDataItem = null;
					GameManager.ClientMgr.NotifyGoodsStallCmd(tcpMgr.MySocketListener, pool, gameClient, 0, num2);
				}
				else if (num2 == 4)
				{
					int goodsDbID = num3;
					int price = Convert.ToInt32(text2);
					if (gameClient.ClientData.StallDataItem != null)
					{
						StallData stallData = gameClient.ClientData.StallDataItem;
						Global.AddGoodsDataIntoStallData(gameClient, goodsDbID, stallData, price);
						GameManager.ClientMgr.NotifyGoodsStallData(tcpMgr.MySocketListener, pool, gameClient, stallData);
					}
				}
				else if (num2 == 5)
				{
					int goodsDbID = num3;
					if (gameClient.ClientData.StallDataItem != null)
					{
						StallData stallData = gameClient.ClientData.StallDataItem;
						Global.RemoveGoodsDataFromStallData(gameClient, goodsDbID, stallData);
						GameManager.ClientMgr.NotifyGoodsStallData(tcpMgr.MySocketListener, pool, gameClient, stallData);
					}
				}
				else if (num2 == 6)
				{
					string stallMessage = text2;
					if (gameClient.ClientData.StallDataItem != null)
					{
						StallData stallData = gameClient.ClientData.StallDataItem;
						lock (stallData)
						{
							stallData.StallMessage = stallMessage;
						}
						GameManager.ClientMgr.NotifyGoodsStallData(tcpMgr.MySocketListener, pool, gameClient, stallData);
					}
				}
				else if (num2 == 7)
				{
					int roleID = num3;
					GameClient gameClient2 = GameManager.ClientMgr.FindClient(roleID);
					if (null == gameClient2)
					{
						GameManager.ClientMgr.NotifyGoodsStallCmd(tcpMgr.MySocketListener, pool, gameClient, -1, num2);
						return TCPProcessCmdResults.RESULT_OK;
					}
					if (gameClient2.ClientData.StallDataItem == null)
					{
						GameManager.ClientMgr.NotifyGoodsStallCmd(tcpMgr.MySocketListener, pool, gameClient, -2, num2);
						return TCPProcessCmdResults.RESULT_OK;
					}
					GameManager.ClientMgr.NotifyGoodsStallData(tcpMgr.MySocketListener, pool, gameClient, gameClient2.ClientData.StallDataItem);
				}
				else if (num2 == 8)
				{
					int roleID = num3;
					int goodsDbID2 = Convert.ToInt32(text2);
					GameClient gameClient2 = GameManager.ClientMgr.FindClient(roleID);
					if (null == gameClient2)
					{
						GameManager.ClientMgr.NotifyGoodsStallCmd(tcpMgr.MySocketListener, pool, gameClient, -1, num2);
						return TCPProcessCmdResults.RESULT_OK;
					}
					if (gameClient2.ClientData.StallDataItem == null)
					{
						GameManager.ClientMgr.NotifyGoodsStallCmd(tcpMgr.MySocketListener, pool, gameClient, -2, num2);
						return TCPProcessCmdResults.RESULT_OK;
					}
					StallData stallData = gameClient2.ClientData.StallDataItem;
					if (stallData != null && stallData.Start > 0)
					{
						int status = Global.BuyFromStallData(gameClient, gameClient2, stallData, goodsDbID2);
						GameManager.ClientMgr.NotifyGoodsStallData(tcpMgr.MySocketListener, pool, gameClient, gameClient2.ClientData.StallDataItem);
						GameManager.ClientMgr.NotifyGoodsStallData(tcpMgr.MySocketListener, pool, gameClient2, gameClient2.ClientData.StallDataItem);
						GameManager.ClientMgr.NotifyGoodsStallCmd(tcpMgr.MySocketListener, pool, gameClient, status, num2);
					}
				}
				return TCPProcessCmdResults.RESULT_OK;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

		private static TCPProcessCmdResults ProcessSpriteTeamCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
