					if (null == petDataByDbID)
					{
						GameManager.ClientMgr.NotifyPetCmd(tcpMgr.MySocketListener, pool, gameClient, -1, num2, num3, "", null);
						return TCPProcessCmdResults.RESULT_OK;
					}
					if (Global.PetOutDBCommand(pool, gameClient, num3) < 0)
					{
						GameManager.ClientMgr.NotifyPetCmd(tcpMgr.MySocketListener, pool, gameClient, -2, num2, num3, "", null);
						return TCPProcessCmdResults.RESULT_OK;
					}
					gameClient.ClientData.PetDbID = num3;
