					Point mapPoint = Global.GetMapPoint(ObjectTypes.OT_CLIENT, gameClient.ClientData.MapCode, gameClient.ClientData.PosX, gameClient.ClientData.PosY, 100);
					double directionByTan = Global.GetDirectionByTan((double)gameClient.ClientData.PosX, (double)gameClient.ClientData.PosY, mapPoint.X, mapPoint.Y);
					string extTag = string.Format("{0}${1}${2}${3}${4}${5}${6}", new object[]
					{
						gameClient.ClientData.PetRoleID,
						petDataByDbID.PetName,
						petDataByDbID.Level,
						petDataByDbID.PetID,
						(int)mapPoint.X,
						(int)mapPoint.Y,
						(int)directionByTan
					});
					gameClient.ClientData.PetPosX = (int)mapPoint.X;
					gameClient.ClientData.PetPosY = (int)mapPoint.Y;
					gameClient.ClientData.ReportPetPosTicks = 0L;
					if (null == list)
					{
						list = Global.GetAll9Clients(gameClient);
					}
					GameManager.ClientMgr.NotifyPetCmd(tcpMgr.MySocketListener, pool, gameClient, 0, num2, num3, extTag, list);
