					{
						GameManager.ClientMgr.NotifyPetCmd(tcpMgr.MySocketListener, pool, gameClient, -1, num2, 0, "", null);
						return TCPProcessCmdResults.RESULT_OK;
					}
					PetData petDataByDbID = Global.GetPetDataByDbID(gameClient, gameClient.ClientData.PetDbID);
					if (null == petDataByDbID)
					{
						GameManager.ClientMgr.NotifyPetCmd(tcpMgr.MySocketListener, pool, gameClient, -2, num2, 0, "", null);
						return TCPProcessCmdResults.RESULT_OK;
					}
					Global.PetInDBCommand(pool, gameClient, petDataByDbID.DbID);
					List<object> list = Global.GetAll9Clients(gameClient);
					GameManager.ClientMgr.NotifyPetCmd(tcpMgr.MySocketListener, pool, gameClient, 0, num2, gameClient.ClientData.PetRoleID, "", list);
					gameClient.ClientData.PetDbID = 0;
					gameClient.ClientData.PetRoleID = -1;
					gameClient.ClientData.PetPosX = 0;
					gameClient.ClientData.PetPosY = 0;
					gameClient.ClientData.ReportPetPosTicks = 0L;
				}
				return TCPProcessCmdResults.RESULT_OK;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

