		private static TCPProcessCmdResults ProcessSpriteUpSkillLevelCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			string text = null;
			try
			{
				text = new UTF8Encoding().GetString(data, 0, count);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				string[] array = text.Split(new char[]
				{
					':'
				});
				if (array.Length != 3)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				int num2 = Convert.ToInt32(array[1]);
				int num3 = Convert.ToInt32(array[2]);
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				SCSkillLevelUp cmdData;
				if (num3 < 1 || num3 > 3)
				{
					cmdData = new SCSkillLevelUp(-100, num, 0, 0, 0);
					gameClient.sendCmd<SCSkillLevelUp>(nID, cmdData, false);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				SkillData skillDataByDbID = Global.GetSkillDataByDbID(gameClient, num2);
				if (null == skillDataByDbID)
				{
					cmdData = new SCSkillLevelUp(-1, num, num2, skillDataByDbID.SkillLevel, skillDataByDbID.UsedNum);
					gameClient.sendCmd<SCSkillLevelUp>(nID, cmdData, false);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int num4;
				if (skillDataByDbID.DbID == -1)
				{
					num4 = gameClient.ClientData.DefaultSkillLev;
				}
				else
				{
					num4 = skillDataByDbID.SkillLevel;
				}
				int occupation = Global.CalcOriginalOccupationID(gameClient);
				SystemXmlItem magicCacheItem = MagicsCacheManager.GetMagicCacheItem(occupation, skillDataByDbID.SkillID, num4);
				if (magicCacheItem == null)
				{
					cmdData = new SCSkillLevelUp(-2, num, num2, skillDataByDbID.SkillLevel, skillDataByDbID.UsedNum);
					gameClient.sendCmd<SCSkillLevelUp>(nID, cmdData, false);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int intValue = magicCacheItem.GetIntValue("NeedZhuanSheng", -1);
				int intValue2 = magicCacheItem.GetIntValue("NeedRoleLevel", -1);
				int intValue3 = magicCacheItem.GetIntValue("ShuLianDu", -1);
				int intValue4 = magicCacheItem.GetIntValue("NeedJinBi", -1);
				int num5 = 0;
				if (skillDataByDbID.DbID < 0)
				{
					num5 = gameClient.ClientData.DefaultSkillUseNum;
				}
				else
				{
					num5 = skillDataByDbID.UsedNum;
				}
				if (num3 != 1)
				{
					int maxSkillLevel = Global.MaxSkillLevel;
					if (num4 >= maxSkillLevel)
					{
						cmdData = new SCSkillLevelUp(-3, num, num2, skillDataByDbID.SkillLevel, skillDataByDbID.UsedNum);
						gameClient.sendCmd<SCSkillLevelUp>(nID, cmdData, false);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					if (gameClient.ClientData.ChangeLifeCount < intValue)
					{
						cmdData = new SCSkillLevelUp(-4, num, num2, skillDataByDbID.SkillLevel, skillDataByDbID.UsedNum);
						gameClient.sendCmd<SCSkillLevelUp>(nID, cmdData, false);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					if (gameClient.ClientData.ChangeLifeCount == intValue)
					{
						if (gameClient.ClientData.Level < intValue2)
						{
							cmdData = new SCSkillLevelUp(-5, num, num2, skillDataByDbID.SkillLevel, skillDataByDbID.UsedNum);
							gameClient.sendCmd<SCSkillLevelUp>(nID, cmdData, false);
							return TCPProcessCmdResults.RESULT_DATA;
						}
					}
					if (gameClient.ClientData.Money1 + gameClient.ClientData.YinLiang < intValue4)
					{
						cmdData = new SCSkillLevelUp(-7, num, num2, skillDataByDbID.SkillLevel, skillDataByDbID.UsedNum);
						gameClient.sendCmd<SCSkillLevelUp>(nID, cmdData, false);
						return TCPProcessCmdResults.RESULT_DATA;
					}
				}
				if (num3 == 1)
				{
					if (num5 < intValue3)
					{
						int num6 = (intValue3 - num5) / 5;
						int tianDiJingYuanValue = GameManager.ClientMgr.GetTianDiJingYuanValue(gameClient);
						if (tianDiJingYuanValue < num6)
						{
							cmdData = new SCSkillLevelUp(-8, num, num2, skillDataByDbID.SkillLevel, skillDataByDbID.UsedNum);
							gameClient.sendCmd<SCSkillLevelUp>(nID, cmdData, false);
							return TCPProcessCmdResults.RESULT_DATA;
						}
						GameManager.ClientMgr.ModifyTianDiJingYuanValue(gameClient, -num6, "升级技能", false, true, false);
						GameManager.ClientMgr.AddNumSkill(gameClient, skillDataByDbID, intValue3 - num5, false);
					}
					num5 = intValue3;
				}
				else if (num3 == 2)
				{
					if (num5 < intValue3)
					{
						cmdData = new SCSkillLevelUp(-9, num, num2, skillDataByDbID.SkillLevel, skillDataByDbID.UsedNum);
						gameClient.sendCmd<SCSkillLevelUp>(nID, cmdData, false);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					GameManager.ClientMgr.AddNumSkill(gameClient, skillDataByDbID, -intValue3, false);
					if (skillDataByDbID.DbID < 0)
					{
						num5 = gameClient.ClientData.DefaultSkillUseNum;
					}
					else
					{
						num5 = skillDataByDbID.UsedNum;
					}
					Global.SubBindTongQianAndTongQian(gameClient, intValue4, "升级技能");
					if (skillDataByDbID.DbID == -1)
					{
						lock (gameClient.ClientData.SkillDataList)
						{
							for (int i = 0; i < gameClient.ClientData.SkillDataList.Count; i++)
							{
								if (gameClient.ClientData.SkillDataList[i].DbID == num2)
								{
									gameClient.ClientData.SkillDataList[i].SkillLevel++;
								}
							}
						}
						gameClient.ClientData.DefaultSkillLev++;
						Global.SaveRoleParamsInt32ValueToDB(gameClient, "DefaultSkillLev", gameClient.ClientData.DefaultSkillLev, true);
					}
					else
					{
						skillDataByDbID.SkillLevel++;
						gameClient.ClientData.TotalLearnedSkillLevelCount++;
						GameManager.ClientMgr.UpdateSkillInfo(gameClient, skillDataByDbID, true);
						Global.RefreshFiveCombatSkillList(gameClient);
					}
					ChengJiuManager.OnRoleSkillLevelUp(gameClient);
					GlobalEventSource.getInstance().fireEvent(SevenDayGoalEvPool.Alloc(gameClient, ESevenDayGoalFuncType.SkillLevelUp));
				}
				else
				{
					if (num5 < intValue3)
					{
						int num6 = (intValue3 - num5) / 5;
						int tianDiJingYuanValue = GameManager.ClientMgr.GetTianDiJingYuanValue(gameClient);
						if (tianDiJingYuanValue < num6)
						{
							cmdData = new SCSkillLevelUp(-8, num, num2, skillDataByDbID.SkillLevel, skillDataByDbID.UsedNum);
							gameClient.sendCmd<SCSkillLevelUp>(nID, cmdData, false);
							return TCPProcessCmdResults.RESULT_DATA;
						}
						GameManager.ClientMgr.ModifyTianDiJingYuanValue(gameClient, -num6, "升级技能", false, true, false);
					}
					GameManager.ClientMgr.AddNumSkill(gameClient, skillDataByDbID, -num5, false);
					if (skillDataByDbID.DbID < 0)
					{
						num5 = gameClient.ClientData.DefaultSkillUseNum;
					}
					else
					{
						num5 = skillDataByDbID.UsedNum;
					}
					Global.SubBindTongQianAndTongQian(gameClient, intValue4, "升级技能");
					if (skillDataByDbID.DbID == -1)
					{
						lock (gameClient.ClientData.SkillDataList)
						{
							for (int i = 0; i < gameClient.ClientData.SkillDataList.Count; i++)
							{
								if (gameClient.ClientData.SkillDataList[i].DbID == num2)
								{
									gameClient.ClientData.SkillDataList[i].SkillLevel++;
								}
							}
						}
						gameClient.ClientData.DefaultSkillLev++;
						Global.SaveRoleParamsInt32ValueToDB(gameClient, "DefaultSkillLev", gameClient.ClientData.DefaultSkillLev, true);
					}
					else
					{
						skillDataByDbID.SkillLevel++;
						gameClient.ClientData.TotalLearnedSkillLevelCount++;
						GameManager.ClientMgr.UpdateSkillInfo(gameClient, skillDataByDbID, true);
						Global.RefreshFiveCombatSkillList(gameClient);
					}
					ChengJiuManager.OnRoleSkillLevelUp(gameClient);
					GlobalEventSource.getInstance().fireEvent(SevenDayGoalEvPool.Alloc(gameClient, ESevenDayGoalFuncType.SkillLevelUp));
				}
				Global.RefreshSecondSkillLevel(gameClient, skillDataByDbID.SkillID);
				cmdData = new SCSkillLevelUp(1, num, num2, skillDataByDbID.SkillLevel, num5);
				gameClient.sendCmd<SCSkillLevelUp>(nID, cmdData, false);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

