		private static TCPProcessCmdResults ProcessSpriteMarketBuyGoodsCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			string text = null;
			try
			{
				text = new UTF8Encoding().GetString(data, 0, count);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				string[] array = text.Split(new char[]
				{
					':'
				});
				if (array.Length != 3)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				int num2 = Convert.ToInt32(array[1]);
				int num3 = Convert.ToInt32(array[2]);
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				if (gameClient.ClientSocket.IsKuaFuLogin)
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				int gameConfigItemInt = GameManager.GameConfigMgr.GetGameConfigItemInt("disable-market", 0);
				if (gameConfigItemInt > 0)
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				GameClient gameClient2 = null;
				SaleGoodsItem saleGoodsItem = SaleGoodsManager.RemoveSaleGoodsItem(num2);
				if (null != saleGoodsItem)
				{
					gameClient2 = GameManager.ClientMgr.FindClient(saleGoodsItem.Client.ClientData.RoleID);
					if (null != gameClient2)
					{
						if (!gameClient2.ClientData.AllowMarketBuy)
						{
							return TCPProcessCmdResults.RESULT_OK;
						}
					}
				}
				if (saleGoodsItem != null && null != gameClient2)
				{
					GoodsData goodsData = Global.GetSaleGoodsDataByDbID(gameClient2, num2);
					if (null == goodsData)
					{
						SaleGoodsManager.AddSaleGoodsItem(saleGoodsItem);
						GameManager.ClientMgr.NotifySpriteMarketBuy(tcpMgr.MySocketListener, pool, gameClient, gameClient2, -3, 0, num2, num3, 226);
						return TCPProcessCmdResults.RESULT_OK;
					}
					if (goodsData.GoodsID != num3)
					{
						SaleGoodsManager.AddSaleGoodsItem(saleGoodsItem);
						GameManager.ClientMgr.NotifySpriteMarketBuy(tcpMgr.MySocketListener, pool, gameClient, gameClient2, -1003, 0, num2, num3, 226);
						return TCPProcessCmdResults.RESULT_OK;
					}
					if (50200 != goodsData.GoodsID)
					{
						if (!Global.CanAddGoods(gameClient, goodsData.GoodsID, goodsData.GCount, 0, goodsData.Endtime, true, false))
						{
							SaleGoodsManager.AddSaleGoodsItem(saleGoodsItem);
							GameManager.ClientMgr.NotifySpriteMarketBuy(tcpMgr.MySocketListener, pool, gameClient, gameClient2, -5, 0, num2, num3, 226);
							return TCPProcessCmdResults.RESULT_OK;
						}
					}
					if (saleGoodsItem.SalingGoodsData.SaleMoney1 > 0 && gameClient.ClientData.YinLiang < saleGoodsItem.SalingGoodsData.SaleMoney1)
					{
						SaleGoodsManager.AddSaleGoodsItem(saleGoodsItem);
						GameManager.ClientMgr.NotifySpriteMarketBuy(tcpMgr.MySocketListener, pool, gameClient, gameClient2, -10, 0, num2, num3, 226);
						return TCPProcessCmdResults.RESULT_OK;
					}
					if (saleGoodsItem.SalingGoodsData.SaleYuanBao > 0 && gameClient.ClientData.UserMoney < saleGoodsItem.SalingGoodsData.SaleYuanBao)
					{
						SaleGoodsManager.AddSaleGoodsItem(saleGoodsItem);
						GameManager.ClientMgr.NotifySpriteMarketBuy(tcpMgr.MySocketListener, pool, gameClient, gameClient2, -20, 0, num2, num3, 226);
						return TCPProcessCmdResults.RESULT_OK;
					}
					int num4 = (int)GameManager.systemParamsList.GetParamValueIntByName("YinPiaoGoodsID", -1);
					if (saleGoodsItem.SalingGoodsData.SaleYinPiao > 0 && Global.GetTotalGoodsCountByID(gameClient, num4) < saleGoodsItem.SalingGoodsData.SaleYinPiao)
					{
						SaleGoodsManager.AddSaleGoodsItem(saleGoodsItem);
						GameManager.ClientMgr.NotifySpriteMarketBuy(tcpMgr.MySocketListener, pool, gameClient, gameClient2, -21, 0, num2, num3, 226);
						return TCPProcessCmdResults.RESULT_OK;
					}
					if (saleGoodsItem.SalingGoodsData.SaleYinPiao > 0)
					{
						if (!Global.CanAddGoods2(gameClient2, num4, saleGoodsItem.SalingGoodsData.SaleYinPiao, 0, "1900-01-01 12:00:00", true))
						{
							SaleGoodsManager.AddSaleGoodsItem(saleGoodsItem);
							GameManager.ClientMgr.NotifySpriteMarketBuy(tcpMgr.MySocketListener, pool, gameClient, gameClient2, -22, 0, num2, num3, 226);
							return TCPProcessCmdResults.RESULT_OK;
						}
					}
					GameManager.logDBCmdMgr.AddMessageLog(-1, "交易日志", "交易市场", gameClient2.ClientData.RoleName, gameClient.ClientData.RoleName, "交易", gameClient.ClientData.RoleID, gameClient.ClientData.ZoneID, gameClient.strUserID, gameClient2.ClientData.RoleID, GameManager.ServerId, "");
					if (saleGoodsItem.SalingGoodsData.SaleMoney1 > 0)
					{
						if (!GameManager.ClientMgr.SubUserYinLiang(tcpMgr.MySocketListener, tcpClientPool, pool, gameClient, saleGoodsItem.SalingGoodsData.SaleMoney1, "交易市场购买1", false))
						{
							SaleGoodsManager.AddSaleGoodsItem(saleGoodsItem);
							GameManager.ClientMgr.NotifySpriteMarketBuy(tcpMgr.MySocketListener, pool, gameClient, gameClient2, -10, 0, num2, num3, 226);
							return TCPProcessCmdResults.RESULT_OK;
						}
						GameManager.ClientMgr.AddUserYinLiang(tcpMgr.MySocketListener, tcpClientPool, pool, gameClient2, saleGoodsItem.SalingGoodsData.SaleMoney1, "交易市场出售1", false);
					}
