				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				string[] array = text.Split(new char[]
				{
					':'
				});
				if (array.Length != 2)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				int num2 = Convert.ToInt32(array[1]);
				GameClient client = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, client, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				HorseData horseDataByDbID = Global.GetHorseDataByDbID(client, num2);
				string data2;
				if (null == horseDataByDbID)
				{
					data2 = string.Format("{0}:{1}:{2}:{3}", new object[]
					{
						-1,
						num,
						num2,
						0
					});
				}
				else
				{
					int goodsID = (int)GameManager.systemParamsList.GetParamValueIntByName("RandColor", -1);
					if (Global.GetTotalGoodsCountByID(client, goodsID) <= 0)
					{
						data2 = string.Format("{0}:{1}:{2}:{3}", new object[]
						{
							-10,
							num,
							num2,
							1
						});
					}
					else
					{
						bool flag = false;
						bool flag2 = false;
						if (!GameManager.ClientMgr.NotifyUseGoods(tcpMgr.MySocketListener, tcpClientPool, pool, client, goodsID, 1, false, out flag, out flag2, false))
						{
							data2 = string.Format("{0}:{1}:{2}:{3}", new object[]
							{
								-10,
								num,
								num2,
								1
							});
						}
						else
						{
							int randomHorseNewBodyID = Global.GetRandomHorseNewBodyID();
							if (randomHorseNewBodyID != horseDataByDbID.BodyID)
							{
								Global.UpdateHorseBodyIDDBCommand(Global._TCPManager.TcpOutPacketPool, client, horseDataByDbID.DbID, randomHorseNewBodyID);
							}
							data2 = string.Format("{0}:{1}:{2}:{3}", new object[]
							{
								0,
								num,
								num2,
								horseDataByDbID.BodyID
							});
						}
					}
				}
				tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

