		private static TCPProcessCmdResults ProcessSpriteClientHeartCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			SCClientHeart scclientHeart = null;
			try
			{
				SingletonTemplate<ProtoChecker>.Instance().Check<SCClientHeart>(data, 0, count, socket.m_Socket);
				if (!CheckHelper.CheckTCPCmdHandle<SCClientHeart>(socket, nID, data, count, out scclientHeart))
				{
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int roleID = scclientHeart.RoleID;
				int randToken = scclientHeart.RandToken;
				long num = (long)scclientHeart.Ticks;
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref roleID))
				{
					SCClientHeart instance = new SCClientHeart(0, (int)TimeUtil.NOW(), 0);
					tcpOutPacket = DataHelper.ObjectToTCPOutPacket<SCClientHeart>(instance, Global._TCPManager.TcpOutPacketPool, 23);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (!tcpRandKey.FindKey(randToken))
				{
					LogManager.WriteLog(2, string.Format("接收到客户端心跳后，检测token无效, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), roleID), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				long num2 = TimeUtil.NOW();
				if (gameClient.ClientData.LastClientHeartTicks < num2 - 60000L)
				{
					int num3 = Global.RegisterUserIDToDBServer(gameClient.strUserID, 1, socket.ServerId, ref socket.session.LastLogoutServerTicks);
					if (num3 > 0)
					{
						gameClient.ClientData.LastClientHeartTicks = num2;
						gameClient.ClientData.ClientHeartCount = gameClient.ClientData.ClientHeartCount + 1;
					}
				}
				int gameConfigItemInt = GameManager.GameConfigMgr.GetGameConfigItemInt("yuzhouticks", 2000);
				SingletonTemplate<SpeedUpTickCheck>.Instance().OnClientHeart(gameClient, scclientHeart.ReportCliRealTick);
				SCClientHeart cmdData = new SCClientHeart(roleID, (int)TimeUtil.NOW(), gameConfigItemInt);
				gameClient.sendCmd<SCClientHeart>(23, cmdData, false);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

