		private static TCPProcessCmdResults ProcessStartYaBiaoCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			string text = null;
			try
			{
				text = new UTF8Encoding().GetString(data, 0, count);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				string[] array = text.Split(new char[]
				{
					':'
				});
				if (array.Length != 3)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				int num2 = Convert.ToInt32(array[1]);
				int num3 = Convert.ToInt32(array[2]);
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				string data2;
				if (gameClient.ClientData.MyYaBiaoData != null && gameClient.ClientData.MyYaBiaoData.YaBiaoID > 0)
				{
					data2 = string.Format("{0}:{1}:{2}", num, num2, -1);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int num4 = 0;
				int num5 = 65536;
				int num6 = 0;
				Global.GetYaBiaoCondition(num2, out num4, out num5, out num6);
				if (gameClient.ClientData.Level < num4 || gameClient.ClientData.Level > num5)
				{
					data2 = string.Format("{0}:{1}:{2}", num, num2, -2);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (gameClient.ClientData.YinLiang < num6)
				{
					data2 = string.Format("{0}:{1}:{2}", num, num2, -3);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (0 >= num3)
				{
					if (!Global.CanTakeNormalYaBiao(gameClient))
					{
						data2 = string.Format("{0}:{1}:{2}", num, num2, -5);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
				}
				else
				{
					num3 = (int)GameManager.systemParamsList.GetParamValueIntByName("YaBiaoLingGoodsID", -1);
					int totalGoodsCountByID = Global.GetTotalGoodsCountByID(gameClient, num3);
					if (totalGoodsCountByID < 1)
					{
						data2 = string.Format("{0}:{1}:{2}", num, num2, -10);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					bool flag = false;
					bool flag2 = false;
					if (!GameManager.ClientMgr.NotifyUseGoods(tcpMgr.MySocketListener, tcpClientPool, pool, gameClient, num3, 1, false, out flag, out flag2, false))
					{
						data2 = string.Format("{0}:{1}:{2}", num, num2, -11);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
				}
				if (!GameManager.ClientMgr.SubUserYinLiang(tcpMgr.MySocketListener, tcpClientPool, pool, gameClient, num6, "接镖", false))
				{
					data2 = string.Format("{0}:{1}:{2}", num, num2, -20);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (null == gameClient.ClientData.MyYaBiaoData)
				{
					gameClient.ClientData.MyYaBiaoData = new YaBiaoData();
				}
				DateTime dateTime = TimeUtil.NowDateTime();
				gameClient.ClientData.MyYaBiaoData.YaBiaoID = num2;
				gameClient.ClientData.MyYaBiaoData.StartTime = dateTime.Ticks / 10000L;
				gameClient.ClientData.MyYaBiaoData.State = 0;
				gameClient.ClientData.MyYaBiaoData.LineID = GameManager.ServerLineID;
				gameClient.ClientData.MyYaBiaoData.TouBao = 0;
				if (num3 <= 0)
				{
					if (dateTime.DayOfYear != gameClient.ClientData.MyYaBiaoData.YaBiaoDayID)
					{
						gameClient.ClientData.MyYaBiaoData.YaBiaoDayID = dateTime.DayOfYear;
						gameClient.ClientData.MyYaBiaoData.YaBiaoNum = 1;
					}
					else
					{
						gameClient.ClientData.MyYaBiaoData.YaBiaoNum++;
					}
				}
				gameClient.ClientData.MyYaBiaoData.TakeGoods = 0;
				GameManager.DBCmdMgr.AddDBCmd(10057, string.Format("{0}:{1}:{2}:{3}:{4}:{5}:{6}:{7}:{8}", new object[]
				{
					gameClient.ClientData.RoleID,
					gameClient.ClientData.MyYaBiaoData.YaBiaoID,
					gameClient.ClientData.MyYaBiaoData.StartTime,
					gameClient.ClientData.MyYaBiaoData.State,
					gameClient.ClientData.MyYaBiaoData.LineID,
					gameClient.ClientData.MyYaBiaoData.TouBao,
					gameClient.ClientData.MyYaBiaoData.YaBiaoDayID,
					gameClient.ClientData.MyYaBiaoData.YaBiaoNum,
					gameClient.ClientData.MyYaBiaoData.TakeGoods
				}), null, gameClient.ServerId);
				GameManager.ClientMgr.NotifyYaBiaoData(gameClient);
				BiaoCheManager.ProcessNewBiaoChe(tcpMgr.MySocketListener, pool, gameClient, num2);
				Global.AddYaBiaoEvent(gameClient, num2, "接镖");
				data2 = string.Format("{0}:{1}:{2}", num, num2, 0);
				tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

		private static TCPProcessCmdResults ProcessEndYaBiaoCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
