		private static TCPProcessCmdResults ProcessTouBaoCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			string text = null;
			try
			{
				text = new UTF8Encoding().GetString(data, 0, count);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				string[] array = text.Split(new char[]
				{
					':'
				});
				if (array.Length != 1)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				string data2;
				if (null == gameClient.ClientData.MyYaBiaoData)
				{
					data2 = string.Format("{0}:{1}", num, -1);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (gameClient.ClientData.MyYaBiaoData.YaBiaoID <= 0)
				{
					data2 = string.Format("{0}:{1}", num, -1);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (gameClient.ClientData.MyYaBiaoData.TouBao > 0)
				{
					data2 = string.Format("{0}:{1}", num, -3);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				bool flag = false;
				long num2 = TimeUtil.NowDateTime().Ticks / 10000L;
				if (num2 - gameClient.ClientData.MyYaBiaoData.StartTime < (long)Global.MaxYaBiaoTicks)
				{
					if (gameClient.ClientData.MyYaBiaoData.State <= 0)
					{
						flag = true;
					}
				}
				if (!flag)
				{
					data2 = string.Format("{0}:{1}", num, -5);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (gameClient.ClientData.MyYaBiaoData.LineID != GameManager.ServerLineID)
				{
					data2 = string.Format("{0}:{1}", num, -6);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int yinLiang = 0;
				int num3 = 0;
				int num4 = 0;
				Global.GetYaBiaoReward(gameClient.ClientData.MyYaBiaoData.YaBiaoID, out yinLiang, out num3, out num4);
				int touBaoYinPiaoNum = Global.GetTouBaoYinPiaoNum(yinLiang);
				if (gameClient.ClientData.UserMoney < touBaoYinPiaoNum)
