				{
					':'
				});
				if (array.Length != 1)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				text += ':';
				text += jieriIPointsExchgActivity.FromDate.Replace(':', '$');
				text += ':';
				text += jieriIPointsExchgActivity.ToDate.Replace(':', '$');
				byte[] bytes = new UTF8Encoding().GetBytes(text);
				TCPProcessCmdResults result = Global.TransferRequestToDBServer(tcpMgr, socket, tcpClientPool, tcpRandKey, pool, nID, bytes, bytes.Length, out tcpOutPacket, socket.ServerId);
