		private static TCPProcessCmdResults ProcessCreateBangHuiCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			string text = null;
			try
			{
				text = new UTF8Encoding().GetString(data, 0, count);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				string[] array = text.Split(new char[]
				{
					':'
				});
				if (array.Length != 3)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				string[] array2 = array[1].Split(new char[]
				{
					'$'
				});
				string bhName = array2[0];
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				string data2;
				if (gameClient.ClientSocket.IsKuaFuLogin)
				{
					data2 = string.Format("{0}:{1}:{2}", -2, num, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				string param = array2[0];
				int num2 = NameServerNamager.CheckInvalidCharacters(param, false);
				if (num2 <= 0)
				{
					data2 = string.Format("{0}:{1}:{2}", (num2 == -40) ? -3 : num2, num, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				num2 = NameServerNamager.RegisterNameToNameServer(gameClient.ClientData.ZoneID, gameClient.strUserID, array2, 1, num);
				if (num2 <= 0)
				{
					data2 = string.Format("{0}:{1}:{2}", num2, num, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (gameClient.ClientData.ChangeLifeCount < Global.CreateBangHuiNeedZhuanShengLevel)
				{
					data2 = string.Format("{0}:{1}:{2}", -1, num, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (gameClient.ClientData.ChangeLifeCount == Global.CreateBangHuiNeedZhuanShengLevel)
				{
					if (gameClient.ClientData.Level < Global.CreateBangHuiNeedLevel)
					{
						data2 = string.Format("{0}:{1}:{2}", -1, num, 0);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
				}
				int createBangHuiNeedGoodsID = Global.CreateBangHuiNeedGoodsID;
				if (createBangHuiNeedGoodsID > 0)
				{
					if (Global.GetTotalGoodsCountByID(gameClient, createBangHuiNeedGoodsID) <= 0)
					{
						data2 = string.Format("{0}:{1}:{2}", -50, num, 0);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
				}
				if (gameClient.ClientData.Money1 + gameClient.ClientData.YinLiang < Global.CreateBangHuiNeedTongQian)
				{
					data2 = string.Format("{0}:{1}:{2}", -10, num, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				text += string.Format(":{0}", Global.GetZhanMengInitCoin());
				string[] array3 = Global.ExecuteDBCmd(nID, text, gameClient.ServerId);
				if (array3 == null || 3 != array3.Length || Convert.ToInt32(array3[0]) < 0)
				{
					int num3 = (array3 != null && array3.Length > 0) ? Convert.ToInt32(array3[0]) : -1031;
					if (num3 == -1031)
					{
						num3 = -1011;
					}
					else
					{
						num3 = -1010;
					}
					data2 = string.Format("{0}:{1}:{2}", num3, num, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int num4 = Convert.ToInt32(array3[0]);
				if (num4 >= 0)
				{
					if (!Global.SubBindTongQianAndTongQian(gameClient, Global.CreateBangHuiNeedTongQian, "创建帮会"))
					{
						data2 = string.Format("{0}:{1}:{2}", -10, num, 0);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					bool flag = false;
					bool flag2 = false;
					if (createBangHuiNeedGoodsID > 0)
					{
						GameManager.ClientMgr.NotifyUseGoods(tcpMgr.MySocketListener, tcpClientPool, pool, gameClient, createBangHuiNeedGoodsID, 1, false, out flag, out flag2, false);
					}
					gameClient.ClientData.Faction = Convert.ToInt32(array3[2]);
					gameClient.ClientData.BHName = Global.FormatBangHuiName(gameClient.ClientData.ZoneID, bhName);
					gameClient.ClientData.BHZhiWu = 1;
					GameManager.ClientMgr.ChangeBangHuiName(tcpMgr.MySocketListener, pool, gameClient);
					GlobalEventSource4Scene.getInstance().fireEvent(new PostBangHuiChangeEventObject(gameClient, gameClient.ClientData.Faction), 10000);
					Global.SaveRoleParamsInt32ValueToDB(gameClient, "EnterBangHuiUnixSecs", DataHelper.UnixSecondsNow(), true);
					Global.SaveRoleParamsDateTimeToDB(gameClient, "10182", TimeUtil.NowDateTime(), true);
					JunQiManager.NotifySyncBangHuiJunQiItemsDict(gameClient);
					Global.BroadcastBangHuiCreateOk(gameClient, gameClient.ClientData.BHName);
					GlobalEventSource.getInstance().fireEvent(ZhanMengShijianEvent.createCreateZhanMengEvent(Global.FormatRoleName4(gameClient), gameClient.ClientData.Faction, gameClient.ServerId));
					ChengJiuManager.OnFirstInFaction(gameClient);
					UnionPalaceManager.initSetUnionPalaceProps(gameClient, true);
					gameClient._IconStateMgr.CheckGuildIcon(gameClient, false);
					EventLogManager.AddBangHuiCreateEvent(gameClient, gameClient.ClientData.Faction);
				}
				data2 = string.Format("{0}:{1}:{2}", num4, num, array3[2]);
				tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

