				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				GameClient gameClient2 = GameManager.ClientMgr.FindClient(num3);
				if (null != gameClient2)
				{
					GameManager.ClientMgr.NotifyRefuseApplyToBHMember(gameClient2, gameClient.ClientData.RoleName, gameClient.ClientData.BHName);
				}
				else
				{
					string text2 = string.Format("-refusetobh {0} {1} {2} {3}", new object[]
					{
						num3,
						gameClient.ClientData.RoleName,
						gameClient.ClientData.BHName,
						0
					});
					GameManager.DBCmdMgr.AddDBCmd(157, string.Format("{0}:{1}:{2}:{3}:{4}:{5}:{6}:{7}:{8}", new object[]
					{
						gameClient.ClientData.RoleID,
						"",
						0,
						"",
						0,
						text2,
						0,
						0,
						GameManager.ServerLineID
					}), null, gameClient.ServerId);
				}
				return TCPProcessCmdResults.RESULT_OK;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

