				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				string[] array = text.Split(new char[]
				{
					':'
				});
				if (array.Length != 4)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				int key = Convert.ToInt32(array[1]);
				int num2 = Convert.ToInt32(array[2]);
				bool flag = 1 == Convert.ToInt32(array[3]);
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				if (num2 <= 0 || num2 >= 2)
				{
					LogManager.WriteLog(2, string.Format("奇珍阁, 非法的外挂购买, 物品数量不能小于等于0或者大于2, CMD={0}, Client={1}, RoleID={2}, GoodsNum={3}", new object[]
					{
						(TCPGameServerCmds)nID,
						Global.GetSocketRemoteEndPoint(socket, false),
						num,
						num2
					}), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				Dictionary<int, QiZhenGeItemData> qiZhenGeGoodsDict = gameClient.ClientData.QiZhenGeGoodsDict;
				if (null == qiZhenGeGoodsDict)
				{
					string data2 = string.Format("{0}:{1}:{2}", -1, num, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (num2 <= 0)
				{
					string data2 = string.Format("{0}:{1}:{2}", -5, num, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				QiZhenGeItemData qiZhenGeItemData = null;
				if (!qiZhenGeGoodsDict.TryGetValue(key, out qiZhenGeItemData))
				{
					string data2 = string.Format("{0}:{1}:{2}", -10, num, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (gameClient.ClientData.QiZhenGeBuyNum >= Global.MaxNumPerRefreshQiZhenGe)
				{
					string data2 = string.Format("{0}:{1}:{2}", -20, num, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int price = qiZhenGeItemData.Price;
				if (price <= 0)
				{
					string data2 = string.Format("{0}:{1}:{2}", -100, num, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int goodsID = qiZhenGeItemData.GoodsID;
				if (goodsID <= 0)
				{
					string data2 = string.Format("{0}:{1}:{2}", -101, num, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (gameClient.ClientData.UserMoney < price * num2)
				{
					string data2 = string.Format("{0}:{1}:{2}", -200, num, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int num3 = Global.GetGoodsGridNumByID(goodsID);
				num3 = Global.GMax(num3, 1);
				int num4 = (num2 - 1) / num3 + 1;
				for (int i = 0; i < num4; i++)
				{
					int num5 = num3;
					if (i >= num4 - 1 && num2 % num3 > 0)
					{
						num5 = num2 % num3;
					}
					string data2;
					if (!Global.CanAddGoods(gameClient, goodsID, num5, 0, "1900-01-01 12:00:00", true, false))
					{
						data2 = string.Format("{0}:{1}:{2}", -300, num, 0);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						tcpMgr.MySocketListener.SendData(socket, tcpOutPacket, true);
						break;
					}
					if (flag)
					{
						if (!GameManager.ClientMgr.SubUserMoney(tcpMgr.MySocketListener, tcpClientPool, pool, gameClient, price * num5, "奇珍阁购买自动扣除", true, true, false, DaiBiSySType.None))
						{
							data2 = string.Format("{0}:{1}:{2}", -400, num, 0);
							tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
							tcpMgr.MySocketListener.SendData(socket, tcpOutPacket, true);
							break;
						}
					}
					else if (!GameManager.ClientMgr.SubUserMoney(tcpMgr.MySocketListener, tcpClientPool, pool, gameClient, price * num5, "奇珍阁购买", true, true, false, DaiBiSySType.None))
					{
						data2 = string.Format("{0}:{1}:{2}", -400, num, 0);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						tcpMgr.MySocketListener.SendData(socket, tcpOutPacket, true);
						break;
					}
					gameClient.ClientData.TotalUsedMoney += price * num5;
					int num6 = Global.AddGoodsDBCommand(pool, gameClient, goodsID, num5, 0, "", 0, 0, 0, "", true, 1, "奇珍阁购买", "1900-01-01 12:00:00", 0, 0, 0, 0, 0, 0, 0, null, null, 0, true);
					if (num6 < 0)
					{
						data2 = string.Format("{0}:{1}:{2}", -500, num, 0);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						tcpMgr.MySocketListener.SendData(socket, tcpOutPacket, true);
						break;
					}
					Global.AddRoleQiZhenGeBuyWithYuanBaoEvent(gameClient, goodsID, num5, price * num5);
					gameClient.ClientData.QiZhenGeBuyNum++;
					data2 = string.Format("{0}:{1}:{2}", num6, goodsID, num5);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					tcpMgr.MySocketListener.SendData(socket, tcpOutPacket, true);
				}
				return TCPProcessCmdResults.RESULT_OK;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

