					':'
				});
				if (array.Length != 2)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				int num2 = Convert.ToInt32(array[1]);
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				GoodsData goodsByDbID = Global.GetGoodsByDbID(gameClient, num2);
				string data2;
				if (null == goodsByDbID)
				{
					data2 = string.Format("{0}:{1}:{2}", -1, num2, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int goodsCatetoriy = Global.GetGoodsCatetoriy(goodsByDbID.GoodsID);
				if (goodsCatetoriy < 0 || goodsCatetoriy > 49)
				{
					data2 = string.Format("{0}:{1}:{2}", -11, num2, 0);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				SystemXmlItem systemXmlItem = null;
				if (!GameManager.SystemGoods.SystemXmlItemDict.TryGetValue(goodsByDbID.GoodsID, out systemXmlItem) || null == systemXmlItem)
				{
					LogManager.WriteLog(1, string.Format("处理修理装备物品时，获取物品xml信息失败: GoodsID={0}", goodsByDbID.GoodsID), null, true);
					data2 = string.Format("{0}:{1}:{2}", -2, num2, goodsByDbID.Strong);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int intValue = systemXmlItem.GetIntValue("PriceTwo", -1);
				int[] intArrayValue = systemXmlItem.GetIntArrayValue("EquipProps", ',');
				if (intArrayValue == null || intArrayValue.Length < 2 || intValue <= 0)
				{
					data2 = string.Format("{0}:{1}:{2}", -3, num2, goodsByDbID.Strong);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				double num3 = (double)intArrayValue[1];
				if (num3 <= 0.0 || (double)goodsByDbID.Strong <= 0.0)
				{
					data2 = string.Format("{0}:{1}:{2}", -4, num2, goodsByDbID.Strong);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int num4 = (int)((double)intValue / 3.0 * (double)goodsByDbID.Strong / num3);
				num4 = Global.RecalcNeedYinLiang(num4);
				if (num4 > gameClient.ClientData.YinLiang || num4 < 0)
				{
					data2 = string.Format("{0}:{1}:{2}", -5, num2, goodsByDbID.Strong);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (!Global.SubBindTongQianAndTongQian(gameClient, num4, "修理装备"))
				{
					data2 = string.Format("{0}:{1}:{2}", -6, num2, goodsByDbID.Strong);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				GameManager.ClientMgr.SubEquipStrong(gameClient, goodsByDbID, goodsByDbID.Strong);
				if (goodsByDbID.Using > 0)
				{
					Global.RefreshEquipPropAndNotify(gameClient);
				}
				data2 = string.Format("{0}:{1}:{2}", 0, num2, 0);
				tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

