				int num4 = Convert.ToInt32(array[3]);
				int num5 = Convert.ToInt32(array[4]);
				if (MapTypes.Normal != Global.GetMapType(num2))
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				SceneUIClasses mapSceneType = Global.GetMapSceneType(num2);
				if (Data.CanTeleportMapHashSet.Contains(mapSceneType))
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
