					return TCPProcessCmdResults.RESULT_FAILED;
				}
				if (Data.FightStateTime > 0L && gameClient.buffManager.IsBuffEnabled(114))
				{
					GameManager.ClientMgr.NotifyImportantMsg(gameClient, GLang.GetLang(639, new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
					return TCPProcessCmdResults.RESULT_OK;
				}
				if (gameClient.ClientSocket.IsKuaFuLogin)
				{
					bool flag = false;
					if (KuaFuMapManager.getInstance().IsKuaFuMap(gameClient.ClientData.MapCode) || CompManager.getInstance().IfInMyselfCompMap(gameClient))
					{
						if (num2 == gameClient.ClientData.MapCode || Global.GetMapSceneType(num2) == 0)
						{
							flag = true;
						}
					}
					if (!flag)
					{
						return TCPProcessCmdResults.RESULT_OK;
					}
				}
				if (gameClient.ClientData.CurrentLifeV <= 0)
				{
					return TCPProcessCmdResults.RESULT_OK;
				}
				bool flag2 = false;
				int vipLevel = gameClient.ClientData.VipLevel;
				if (vipLevel > 0 && vipLevel >= 1)
				{
					flag2 = true;
				}
				if (!flag2)
				{
					if (num5 <= 0)
					{
						if (Global.GetFreeChuanSongNum(gameClient) <= 0)
						{
							GameManager.ClientMgr.NotifyImportantMsg(tcpMgr.MySocketListener, pool, gameClient, StringUtil.substitute(GLang.GetLang(640, new object[0]), new object[0]), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 26);
							return TCPProcessCmdResults.RESULT_OK;
						}
						Global.AddFreeChuanSongNum(gameClient);
						GameManager.ClientMgr.NotifyImportantMsg(tcpMgr.MySocketListener, pool, gameClient, StringUtil.substitute(GLang.GetLang(641, new object[0]), new object[]
						{
							Global.GetFreeChuanSongNum(gameClient)
						}), GameInfoTypeIndexes.Hot, ShowGameInfoTypes.ErrAndBox, 0);
					}
					else
					{
						bool flag3 = false;
						GoodsData goodsByID = Global.GetGoodsByID(gameClient, Global.MapTransGoodsID);
						if (null != goodsByID)
						{
							if (GameManager.ClientMgr.NotifyUseGoods(tcpMgr.MySocketListener, tcpClientPool, pool, gameClient, goodsByID.Id, false, false))
							{
								flag3 = true;
							}
						}
						else
						{
							goodsByID = Global.GetGoodsByID(gameClient, Global.MapTransGoodsID2);
							if (null != goodsByID)
							{
								if (GameManager.ClientMgr.NotifyUseGoods(tcpMgr.MySocketListener, tcpClientPool, pool, gameClient, goodsByID.Id, false, false))
								{
									flag3 = true;
								}
							}
						}
						if (!flag3)
						{
							GameManager.ClientMgr.NotifyImportantMsg(tcpMgr.MySocketListener, pool, gameClient, StringUtil.substitute(GLang.GetLang(642, new object[0]), new object[]
							{
								Global.GetGoodsNameByID(Global.MapTransGoodsID)
							}), GameInfoTypeIndexes.Error, ShowGameInfoTypes.ErrAndBox, 0);
							return TCPProcessCmdResults.RESULT_OK;
						}
					}
				}
				GameMap gameMap = null;
				if (GameManager.MapMgr.DictMaps.TryGetValue(num2, out gameMap))
				{
					int num6 = num3;
					int num7 = num4;
					Point mapPoint = Global.GetMapPoint(ObjectTypes.OT_CLIENT, num2, num6, num7, 60);
					num6 = (int)mapPoint.X;
					num7 = (int)mapPoint.Y;
					gameClient.ClientData.CurrentAction = 0;
					if (num2 == gameClient.ClientData.MapCode)
					{
						if (!Global.InObs(ObjectTypes.OT_CLIENT, gameClient.ClientData.MapCode, num6, num7, 0, 0))
						{
							GameManager.ClientMgr.ChangePosition(Global._TCPManager.MySocketListener, Global._TCPManager.TcpOutPacketPool, gameClient, num6, num7, gameClient.ClientData.RoleDirection, 159, 0);
						}
					}
					else
					{
						if (KuaFuMapManager.getInstance().IsKuaFuMap(gameClient.ClientData.MapCode) && !KuaFuMapManager.getInstance().IsKuaFuMap(num2))
						{
							Point point = Global.PixelToGrid(num2, mapPoint);
							Global.ModifyMapRecordData(gameClient, (ushort)num2, (ushort)point.X, (ushort)point.Y, 0);
							KuaFuManager.getInstance().GotoLastMap(gameClient);
							return TCPProcessCmdResults.RESULT_OK;
						}
						if (!Global.InObs(ObjectTypes.OT_CLIENT, num2, num6, num7, 0, 0))
						{
							int randomNumber = Global.GetRandomNumber(0, 8);
							GameManager.ClientMgr.NotifyChangeMap(tcpMgr.MySocketListener, pool, gameClient, num2, num6, num7, randomNumber, 0);
						}
					}
				}
				return TCPProcessCmdResults.RESULT_OK;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

