										return TCPProcessCmdResults.RESULT_DATA;
									}
								}
								if (mailData.Tongqian < 0)
								{
									if (!MoneyUtil.CostMoney(gameClient, 1, modifyValue3, ref text3, "领取邮件扣除绑金", false))
									{
										GameManager.ClientMgr.NotifyHintMsg(gameClient, GLang.GetLang(535, new object[0]));
										text2 = string.Format("{0}:{1}:{2}", -1, num, 0);
										tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, text2, nID);
										return TCPProcessCmdResults.RESULT_DATA;
									}
								}
								if (mailData.Tongqian > 0)
								{
									GameManager.ClientMgr.AddMoney1(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, gameClient, mailData.Tongqian, "提取邮件", false);
									GameManager.SystemServerEvents.AddEvent(string.Format("角色提取邮件获取金币, roleID={0}({1}), Money={2}, newMoney={3}", new object[]
									{
										gameClient.ClientData.RoleID,
										gameClient.ClientData.RoleName,
										gameClient.ClientData.Money1,
										mailData.Tongqian
									}), EventLevels.Record);
								}
								if (mailData.Yinliang > 0)
								{
									GameManager.ClientMgr.AddUserYinLiang(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, gameClient, mailData.Yinliang, "提取邮件", false);
									GameManager.SystemServerEvents.AddEvent(string.Format("角色提取邮件获取银两, roleID={0}({1}), Money={2}, newMoney={3}", new object[]
									{
										gameClient.ClientData.RoleID,
										gameClient.ClientData.RoleName,
										gameClient.ClientData.YinLiang,
										mailData.Yinliang
									}), EventLevels.Record);
								}
								if (mailData.YuanBao > 0)
								{
									GameManager.ClientMgr.AddUserMoney(Global._TCPManager.MySocketListener, Global._TCPManager.tcpClientPool, Global._TCPManager.TcpOutPacketPool, gameClient, mailData.YuanBao, "提取邮件", ActivityTypes.None, "");
									GameManager.SystemServerEvents.AddEvent(string.Format("角色提取邮件获取元宝, roleID={0}({1}), Money={2}, newMoney={3}", new object[]
									{
										gameClient.ClientData.RoleID,
										gameClient.ClientData.RoleName,
										gameClient.ClientData.UserMoney,
										mailData.YuanBao
									}), EventLevels.Record);
								}
								Global.AddRoleFetchMailMoneyEvent(gameClient, mailData.YuanBao, mailData.Yinliang, mailData.Tongqian);
								int num6 = 0;
								if (mailData.GoodsList != null && mailData.GoodsList.Count > 0)
								{
									foreach (MailGoodsData mailGoodsData in mailData.GoodsList)
									{
										GoodsData goodsData = new GoodsData
										{
											Id = -1,
											GoodsID = mailGoodsData.GoodsID,
											Using = 0,
											Forge_level = mailGoodsData.Forge_level,
											Starttime = "1900-01-01 12:00:00",
											Endtime = "1900-01-01 12:00:00",
											Site = mailGoodsData.Site,
											Quality = mailGoodsData.Quality,
											Props = mailGoodsData.Props,
