											AddPropIndex = mailGoodsData.AddPropIndex,
											BornIndex = mailGoodsData.BornIndex,
											Lucky = mailGoodsData.Lucky,
											Strong = mailGoodsData.Strong,
											ExcellenceInfo = mailGoodsData.ExcellenceInfo,
											AppendPropLev = mailGoodsData.AppendPropLev,
											ChangeLifeLevForEquip = mailGoodsData.EquipChangeLifeLev
										};
