										{
											byte[] array4 = Convert.FromBase64String(mailGoodsData.Jewellist);
											goodsData.WashProps = DataHelper.BytesToObject<List<int>>(array4, 0, array4.Length);
											goodsData.Jewellist = "";
										}
										if (mailGoodsData.Props != "" && mailGoodsData.Props != "*")
										{
											byte[] array5 = Convert.FromBase64String(mailGoodsData.Props);
											goodsData.ElementhrtsProps = DataHelper.BytesToObject<List<int>>(array5, 0, array5.Length);
											goodsData.Props = "";
										}
										if (mailGoodsData.OrigHoleNum > 0)
										{
											goodsData.JuHunID = mailGoodsData.OrigHoleNum;
										}
										if (goodsData.AppendPropLev > 0)
										{
											int goodsAppendMax = TCPCmdHandler.getGoodsAppendMax(goodsData);
											if (mailGoodsData.AppendPropLev > goodsAppendMax)
											{
												goodsData.AppendPropLev = goodsAppendMax;
											}
										}
										goodsData.Id = Global.AddGoodsDBCommand(Global._TCPManager.TcpOutPacketPool, gameClient, goodsData.GoodsID, goodsData.GCount, goodsData.Quality, goodsData.Props, goodsData.Forge_level, goodsData.Binding, goodsData.Site, goodsData.Jewellist, true, 1, "提取邮件获取", goodsData.Endtime, goodsData.AddPropIndex, goodsData.BornIndex, goodsData.Lucky, goodsData.Strong, goodsData.ExcellenceInfo, goodsData.AppendPropLev, goodsData.ChangeLifeLevForEquip, goodsData.WashProps, goodsData.ElementhrtsProps, goodsData.JuHunID, true);
