		}

		private static int getGoodsAppendMax(GoodsData goodsData)
		{
			int equipExcellencePropNum = Global.GetEquipExcellencePropNum(goodsData);
			int result;
			if (equipExcellencePropNum == 0)
			{
				result = 20;
			}
			else if (equipExcellencePropNum >= 1 && equipExcellencePropNum <= 2)
			{
				result = 40;
			}
			else if (equipExcellencePropNum >= 3 && equipExcellencePropNum <= 4)
			{
				result = 60;
			}
			else if (equipExcellencePropNum >= 5 && equipExcellencePropNum <= 6)
			{
				result = 80;
			}
			else
			{
				result = 80;
			}
			return result;
		}

