					if (num3 < 0)
					{
						data2 = string.Format("{0}:{1}", num3, num);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					num2 += int.Parse(array3[1]);
				}
				if (num2 > 0)
				{
					int num3 = GameManager.ShengXiaoGuessMgr.SubNeedGoods(client, num2, allowAutoBuy);
					if (num3 < 0)
					{
						data2 = string.Format("{0}:{1}", num3, num);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
				}
				for (int i = 0; i < array2.Length; i++)
				{
					string[] array3 = array2[i].Split(new char[]
					{
						'_'
					});
					int num3 = GameManager.ShengXiaoGuessMgr.AddGuess(client, int.Parse(array3[0]), int.Parse(array3[1]), false);
					if (num3 < 0)
					{
						LogManager.WriteLog(2, string.Format("添加竞猜注码时出错, CMD={0}, Client={1}, RoleID={2}, ret={3}", new object[]
						{
							(TCPGameServerCmds)nID,
							Global.GetSocketRemoteEndPoint(socket, false),
							num,
							num3
						}), null, true);
					}
				}
				data2 = string.Format("{0}:{1}", 1, num);
				tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

