				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				List<int> list = new List<int>();
				for (int i = 1; i <= 7; i++)
				{
					int num3 = Global.GetRoleParamsInt32FromDB(gameClient, string.Format("{0}{1}", "KaiFuOnlineDayTimes_", i));
					if (list.Count > 0)
					{
						num3 = Math.Max(num3, list[list.Count - 1]);
					}
					list.Add(num3);
				}
				int value = 0;
				int num4 = 0;
				if (HuodongCachingMgr.GetCurrentDayKaiFuOnlineSecs(gameClient, out value, out num4))
				{
					num4--;
					if (num4 >= 0 && num4 < list.Count)
					{
						list[num4] = value;
						for (int i = num4 + 1; i < list.Count; i++)
						{
							list[i] = Math.Max(list[i - 1], list[i]);
						}
					}
				}
				byte[] array2 = null;
				if (TCPProcessCmdResults.RESULT_FAILED == Global.TransferRequestToDBServer2(tcpMgr, socket, tcpClientPool, tcpRandKey, pool, 10114, data, count, out array2, gameClient.ServerId))
				{
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num5 = BitConverter.ToInt32(array2, 0);
				List<KaiFuOnlineAwardData> kaiFuOnlineAwardDataList = DataHelper.BytesToObject<List<KaiFuOnlineAwardData>>(array2, 6, num5 - 2);
				KaiFuOnlineInfoData kaiFuOnlineInfoData = new KaiFuOnlineInfoData
				{
					SelfDayBit = Global.GetRoleParamsInt32FromDB(gameClient, "KaiFuOnlineDayBit"),
					SelfDayOnlineSecsList = list,
					KaiFuOnlineAwardDataList = kaiFuOnlineAwardDataList
				};
				int num6 = Global.GetDaysSpanNum(TimeUtil.NowDateTime(), Global.GetKaiFuTime(), true);
				num6++;
				if (num6 >= 1 && num6 <= 7)
				{
					if (num6 > 1)
					{
						HuodongCachingMgr.FixKaiFuOnlineAwardDataList(kaiFuOnlineInfoData.KaiFuOnlineAwardDataList, num4 - 1, gameClient.ServerId);
					}
					HuodongCachingMgr.FixKaiFuOnlineAwardDataList(kaiFuOnlineInfoData.KaiFuOnlineAwardDataList, num4, gameClient.ServerId);
				}
				tcpOutPacket = DataHelper.ObjectToTCPOutPacket<KaiFuOnlineInfoData>(kaiFuOnlineInfoData, pool, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, "", false, false);
			}
			tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, "0", 30767);
			return TCPProcessCmdResults.RESULT_DATA;
		}

