			{
				text = new UTF8Encoding().GetString(data, 0, count);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				string[] array = text.Split(new char[]
				{
					':'
				});
				if (array.Length != 3)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				int num2 = Convert.ToInt32(array[1]);
				int num3 = Convert.ToInt32(array[2]);
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				string data2;
				if (num3 <= 0)
				{
					data2 = string.Format("{0}:{1}", 1, num);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int roleParamsInt32FromDB = Global.GetRoleParamsInt32FromDB(gameClient, "TotalPropPoint");
				int roleParamsInt32FromDB2 = Global.GetRoleParamsInt32FromDB(gameClient, "PropStrength");
				int roleParamsInt32FromDB3 = Global.GetRoleParamsInt32FromDB(gameClient, "PropIntelligence");
				int roleParamsInt32FromDB4 = Global.GetRoleParamsInt32FromDB(gameClient, "PropDexterity");
				int roleParamsInt32FromDB5 = Global.GetRoleParamsInt32FromDB(gameClient, "PropConstitution");
				int num4 = roleParamsInt32FromDB - roleParamsInt32FromDB2 - roleParamsInt32FromDB3 - roleParamsInt32FromDB4 - roleParamsInt32FromDB5;
				if (num4 < num3)
				{
					data2 = string.Format("{0}:{1}", -1, num);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				switch (num2)
				{
				case 0:
					gameClient.ClientData.PropStrength += num3;
					Global.SaveRoleParamsInt32ValueToDB(gameClient, "PropStrength", gameClient.ClientData.PropStrength, true);
					break;
				case 1:
					gameClient.ClientData.PropIntelligence += num3;
					Global.SaveRoleParamsInt32ValueToDB(gameClient, "PropIntelligence", gameClient.ClientData.PropIntelligence, true);
					break;
				case 2:
					gameClient.ClientData.PropDexterity += num3;
					Global.SaveRoleParamsInt32ValueToDB(gameClient, "PropDexterity", gameClient.ClientData.PropDexterity, true);
					break;
				case 3:
					gameClient.ClientData.PropConstitution += num3;
					Global.SaveRoleParamsInt32ValueToDB(gameClient, "PropConstitution", gameClient.ClientData.PropConstitution, true);
					break;
				}
				GameManager.ClientMgr.NotifyUpdateEquipProps(tcpMgr.MySocketListener, pool, gameClient);
				gameClient.ClientData.LifeV = (int)RoleAlgorithm.GetMaxLifeV(gameClient);
				gameClient.ClientData.MagicV = (int)RoleAlgorithm.GetMaxMagicV(gameClient);
				if (gameClient.ClientData.CurrentLifeV > gameClient.ClientData.LifeV)
				{
					gameClient.ClientData.CurrentLifeV = gameClient.ClientData.LifeV;
				}
				if (gameClient.ClientData.CurrentMagicV > gameClient.ClientData.MagicV)
				{
					gameClient.ClientData.CurrentMagicV = gameClient.ClientData.MagicV;
				}
				GameManager.ClientMgr.NotifySelfLifeChanged(Global._TCPManager.MySocketListener, pool, gameClient);
				data2 = string.Format("{0}:{1}", 1, num);
				tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

		private static TCPProcessCmdResults ProcessExecuteRecommendPropAddPointCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			CSPropAddPoint cspropAddPoint = null;
			try
			{
				SingletonTemplate<ProtoChecker>.Instance().Check<CSPropAddPoint>(data, 0, count, socket.m_Socket);
				if (!CheckHelper.CheckTCPCmdHandle<CSPropAddPoint>(socket, nID, data, count, out cspropAddPoint))
				{
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int roleID = cspropAddPoint.RoleID;
				int strength = cspropAddPoint.Strength;
				int intelligence = cspropAddPoint.Intelligence;
				int dexterity = cspropAddPoint.Dexterity;
				int constitution = cspropAddPoint.Constitution;
				long num = (long)strength + (long)intelligence + (long)dexterity + (long)constitution;
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref roleID))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), roleID), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				string data2;
				if (strength < 0 || intelligence < 0 || dexterity < 0 || constitution < 0 || num <= 0L)
				{
					data2 = string.Format("{0}:{1}", -1, roleID);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int roleParamsInt32FromDB = Global.GetRoleParamsInt32FromDB(gameClient, "TotalPropPoint");
				int roleParamsInt32FromDB2 = Global.GetRoleParamsInt32FromDB(gameClient, "PropStrength");
				int roleParamsInt32FromDB3 = Global.GetRoleParamsInt32FromDB(gameClient, "PropIntelligence");
				int roleParamsInt32FromDB4 = Global.GetRoleParamsInt32FromDB(gameClient, "PropDexterity");
				int roleParamsInt32FromDB5 = Global.GetRoleParamsInt32FromDB(gameClient, "PropConstitution");
				int num2 = roleParamsInt32FromDB - roleParamsInt32FromDB2 - roleParamsInt32FromDB3 - roleParamsInt32FromDB4 - roleParamsInt32FromDB5;
				if ((long)num2 < num)
				{
					data2 = string.Format("{0}:{1}", -1, roleID);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				gameClient.ClientData.PropStrength += strength;
				Global.SaveRoleParamsInt32ValueToDB(gameClient, "PropStrength", gameClient.ClientData.PropStrength, true);
				gameClient.ClientData.PropIntelligence += intelligence;
				Global.SaveRoleParamsInt32ValueToDB(gameClient, "PropIntelligence", gameClient.ClientData.PropIntelligence, true);
				gameClient.ClientData.PropDexterity += dexterity;
				Global.SaveRoleParamsInt32ValueToDB(gameClient, "PropDexterity", gameClient.ClientData.PropDexterity, true);
				gameClient.ClientData.PropConstitution += constitution;
				Global.SaveRoleParamsInt32ValueToDB(gameClient, "PropConstitution", gameClient.ClientData.PropConstitution, true);
				Global.RefreshEquipProp(gameClient);
				gameClient.ClientData.LifeV = (int)RoleAlgorithm.GetMaxLifeV(gameClient);
				gameClient.ClientData.MagicV = (int)RoleAlgorithm.GetMaxMagicV(gameClient);
				if (gameClient.ClientData.CurrentLifeV > gameClient.ClientData.LifeV)
				{
					gameClient.ClientData.CurrentLifeV = gameClient.ClientData.LifeV;
				}
				if (gameClient.ClientData.CurrentMagicV > gameClient.ClientData.MagicV)
				{
					gameClient.ClientData.CurrentMagicV = gameClient.ClientData.MagicV;
				}
				GameManager.ClientMgr.NotifyUpdateEquipProps(tcpMgr.MySocketListener, pool, gameClient);
				GameManager.ClientMgr.NotifySelfLifeChanged(Global._TCPManager.MySocketListener, pool, gameClient);
				data2 = string.Format("{0}:{1}", 1, roleID);
				tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

