				{
					data2 = string.Format("{0}:{1}", -2, num);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int dayOfYear = TimeUtil.NowDateTime().DayOfYear;
				VipDailyData vipDailyData = Global.FindVipDailyDataByPriority(gameClient, num2);
				if (null != vipDailyData)
				{
					int vipPriorityDailyMaxUseTimes = Global.GetVipPriorityDailyMaxUseTimes(num2);
					int dailyMaxUseTimes = vipdataInfo.DailyMaxUseTimes;
					if (dailyMaxUseTimes >= vipPriorityDailyMaxUseTimes)
					{
