					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num2 = Convert.ToInt32(array[1]);
				string data2;
				if (num2 < 1 && num2 > VIPEumValue.VIPENUMVALUE_MAXLEVEL)
				{
					data2 = string.Format("{0}:0", -4);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (gameClient.ClientData.VipLevel < 1 && gameClient.ClientData.VipLevel > VIPEumValue.VIPENUMVALUE_MAXLEVEL)
				{
					data2 = string.Format("{0}:0", -1);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (num2 > gameClient.ClientData.VipLevel)
				{
					data2 = string.Format("{0}:0", -4);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				Global.QueryVipAwardFlagToDB(gameClient);
				int num3 = gameClient.ClientData.VipAwardFlag & Global.GetBitValue(num2 + 1);
				if (num3 > 0)
				{
					data2 = string.Format("{0}:0", -2);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				VIPLevAwardAndExpInfo viplevAwardAndExpInfo = null;
				if (!Data.VIPLevAwardAndExpInfoList.TryGetValue(num2, out viplevAwardAndExpInfo) || viplevAwardAndExpInfo == null)
				{
					data2 = string.Format("{0}:0", -3);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				List<GoodsData> awardList = viplevAwardAndExpInfo.AwardList;
				if (awardList == null)
				{
					data2 = string.Format("{0}:0", -3);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (!Global.CanAddGoodsDataList(gameClient, awardList))
				{
					data2 = string.Format("{0}:0", -4);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (awardList.Count > 0)
				{
					for (int i = 0; i < awardList.Count; i++)
					{
						Global.AddGoodsDBCommand(Global._TCPManager.TcpOutPacketPool, gameClient, awardList[i].GoodsID, awardList[i].GCount, 0, "", awardList[i].Forge_level, awardList[i].Binding, 0, "", true, 1, "VIP奖励", "1900-01-01 12:00:00", 0, 0, awardList[i].Lucky, 0, awardList[i].ExcellenceInfo, awardList[i].AddPropIndex, 0, null, null, 0, true);
					}
					gameClient.ClientData.AddAwardRecord(RoleAwardMsg.VIPAward, awardList, false);
				}
				GameManager.ClientMgr.NotifyGetAwardMsg(gameClient, RoleAwardMsg.VIPAward, "");
				gameClient.ClientData.VipAwardFlag |= Global.SetIntSomeBit(num2, num3, true);
				Global.UpdateVipAwardFlagToDB(gameClient, gameClient.ClientData.VipAwardFlag);
				if (gameClient._IconStateMgr.CheckVIPLevelAwardState(gameClient))
				{
					gameClient._IconStateMgr.SendIconStateToClient(gameClient);
				}
				if (gameClient._IconStateMgr.CheckJieRiFanLi(gameClient, ActivityTypes.JieriVIPFanli))
				{
					gameClient._IconStateMgr.AddFlushIconState(14000, gameClient._IconStateMgr.IsAnyJieRiTipActived());
					gameClient._IconStateMgr.SendIconStateToClient(gameClient);
				}
				data2 = string.Format("{0}:{1}", 1, gameClient.ClientData.VipAwardFlag);
				tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

