		private static TCPProcessCmdResults ProcessAdrationPKKingCmd(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPRandKey tcpRandKey, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			string text = null;
			try
			{
				text = new UTF8Encoding().GetString(data, 0, count);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				string[] array = text.Split(new char[]
				{
					':'
				});
				if (array.Length != 2)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				GameClient gameClient = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, gameClient, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				if (!GlobalNew.IsExtraGongNengOpen(gameClient, ExtraGongNengIds.DiaoXiangMoBai))
				{
					LogManager.WriteLog(2, string.Format("接收到了异常的雕像膜拜指令(CMD_SPR_ADRATIONPKKING),角色:{0}", Global.FormatRoleName4(gameClient)), null, true);
					return TCPProcessCmdResults.RESULT_OK;
				}
				int num2 = Global.SafeConvertToInt32(GameManager.GameConfigMgr.GetGameConifgItem("PKKingRole"));
				string data2;
				if (num2 < 0)
				{
					data2 = string.Format("{0}", -1);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int num3 = Data.PKkingadrationData.AdrationMaxLimit;
				int roleParamsInt32FromDB = Global.GetRoleParamsInt32FromDB(gameClient, "PKKingAdmireCount");
				if (num2 == num)
				{
					int num4 = (int)GameManager.systemParamsList.GetParamValueIntByName("PkKingMoBaiNum", -1);
					num3 += num4;
				}
				int vipLevel = gameClient.ClientData.VipLevel;
				int[] paramValueIntArrayByName = GameManager.systemParamsList.GetParamValueIntArrayByName("VIPMoBaiNum", ',');
				if (vipLevel > VIPEumValue.VIPENUMVALUE_MAXLEVEL || paramValueIntArrayByName.Length < 1)
				{
					data2 = string.Format("{0}", -2);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				num3 += paramValueIntArrayByName[vipLevel];
				double num5 = 0.0;
				JieRiMultAwardActivity jieRiMultAwardActivity = HuodongCachingMgr.GetJieRiMultAwardActivity();
				if (null != jieRiMultAwardActivity)
				{
					JieRiMultConfig config = jieRiMultAwardActivity.GetConfig(12);
					if (null != config)
					{
						num5 += config.GetMult();
					}
				}
				SpecPriorityActivity specPriorityActivity = HuodongCachingMgr.GetSpecPriorityActivity();
				if (null != specPriorityActivity)
				{
					num5 += specPriorityActivity.GetMult(SpecPActivityBuffType.SPABT_Admire);
				}
				num5 = Math.Max(1.0, num5);
				num3 = (int)((double)num3 * num5);
				if (roleParamsInt32FromDB >= num3)
				{
					data2 = string.Format("{0}", -3);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int num6 = Convert.ToInt32(array[1]);
				double num7;
				if (gameClient.ClientData.ChangeLifeCount == 0)
				{
					num7 = 1.0;
				}
				else
				{
					num7 = Data.ChangeLifeEverydayExpRate[gameClient.ClientData.ChangeLifeCount];
				}
				if (num6 == 1)
				{
					if (!Global.SubBindTongQianAndTongQian(gameClient, Data.PKkingadrationData.GoldAdrationSpend, "崇拜PK之王多倍经验"))
					{
						data2 = string.Format("{0}", -4);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					int num8 = (int)(num7 * (double)Data.PKkingadrationData.GoldAdrationExpModulus);
					if (num8 > 0)
					{
						GameManager.ClientMgr.ProcessRoleExperience(gameClient, (long)num8, true, true, false, "none");
					}
					GameManager.ClientMgr.ModifyShengWangValue(gameClient, Data.PKkingadrationData.GoldAdrationShengWangModulus, "崇拜PK之王(金币)", true, true);
				}
				else
				{
					if (num6 != 2)
					{
						data2 = string.Format("{0}", -3);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					if (!GameManager.ClientMgr.SubUserMoney(tcpMgr.MySocketListener, tcpClientPool, pool, gameClient, Data.PKkingadrationData.DiamondAdrationSpend, "崇拜PK之王", true, true, false, DaiBiSySType.None))
					{
						data2 = string.Format("{0}", -5);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					int num8 = (int)(num7 * (double)Data.PKkingadrationData.DiamondAdrationExpModulus);
					if (num8 > 0)
					{
						GameManager.ClientMgr.ProcessRoleExperience(gameClient, (long)num8, true, true, false, "none");
					}
					GameManager.ClientMgr.ModifyShengWangValue(gameClient, Data.PKkingadrationData.DiamondAdrationShengWangModulus, "崇拜PK之王(钻石)", true, true);
				}
				Global.ProcessIncreasePKKingAdmireCount(gameClient);
				data2 = string.Format("{0}", 1);
				tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

