					return TCPProcessCmdResults.RESULT_DATA;
				}
				int roleParamsInt32FromDB = Global.GetRoleParamsInt32FromDB(gameClient, "LLCZAdmireDayID");
				int offsetDayNow = Global.GetOffsetDayNow();
