						data2 = string.Format("{0}", -3);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					if (!GameManager.ClientMgr.SubUserMoney(tcpMgr.MySocketListener, tcpClientPool, pool, gameClient, Data.LLCZadrationData.DiamondAdrationSpend, "崇拜罗兰城主", true, true, false, DaiBiSySType.None))
					{
						data2 = string.Format("{0}", -5);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
					int num7 = (int)(num6 * (double)Data.LLCZadrationData.DiamondAdrationExpModulus);
					if (num7 > 0)
					{
						GameManager.ClientMgr.ProcessRoleExperience(gameClient, (long)num7, true, true, false, "none");
					}
					GameManager.ClientMgr.ModifyShengWangValue(gameClient, Data.LLCZadrationData.DiamondAdrationShengWangModulus, "崇拜PK之王(钻石)", true, true);
				}
				Global.SaveRoleParamsInt32ValueToDB(gameClient, "LLCZAdmireCount", roleParamsInt32FromDB2 + 1, true);
				data2 = string.Format("{0}", 1);
				tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
