					return TCPProcessCmdResults.RESULT_FAILED;
				}
				if (array.Length < 2 || Convert.ToInt32(array[1]) != 0)
				{
					Dictionary<int, int> dictionary = new Dictionary<int, int>();
					JieRiMultAwardActivity jieRiMultAwardActivity = HuodongCachingMgr.GetJieRiMultAwardActivity();
					if (jieRiMultAwardActivity != null && jieRiMultAwardActivity.activityDict != null)
					{
						foreach (JieRiMultConfig jieRiMultConfig in jieRiMultAwardActivity.activityDict.Values)
						{
							if (jieRiMultConfig.InActivityTime() && jieRiMultConfig.Effective == 1)
							{
								dictionary[jieRiMultConfig.type] = 1;
							}
						}
					}
					gameClient.sendCmd<Dictionary<int, int>>(nID, dictionary, false);
				}
				else
				{
					Dictionary<int, JieRiFanBeiItemData> dictionary2 = new Dictionary<int, JieRiFanBeiItemData>();
					JieRiMultAwardActivity jieRiMultAwardActivity = HuodongCachingMgr.GetJieRiMultAwardActivity();
					if (jieRiMultAwardActivity != null && jieRiMultAwardActivity.activityDict != null)
					{
						foreach (JieRiMultConfig jieRiMultConfig in jieRiMultAwardActivity.activityDict.Values)
						{
							if (jieRiMultConfig.InActivityTime() && jieRiMultConfig.Effective == 1)
							{
								dictionary2[jieRiMultConfig.type] = new JieRiFanBeiItemData
								{
									Type = jieRiMultConfig.type,
									IsOpen = 1
								};
							}
						}
					}
					JieRiFuLiActivity jieriFuLiActivity = HuodongCachingMgr.GetJieriFuLiActivity();
					if (jieriFuLiActivity != null)
					{
						for (int i = 1; i < 7; i++)
						{
							object obj;
							if (jieriFuLiActivity.IsOpened((EJieRiFuLiType)i, out obj))
							{
								JieRiFanBeiItemData jieRiFanBeiItemData = new JieRiFanBeiItemData();
								jieRiFanBeiItemData.Type = i + 100;
								jieRiFanBeiItemData.IsOpen = 1;
								if (i == 4)
								{
									jieRiFanBeiItemData.ExtArg1 = GameManager.systemParamsList.GetParamValueByName("ForgeMaxOpen");
									jieRiFanBeiItemData.ExtArg2 = GameManager.systemParamsList.GetParamValueByName("ForgeProtectOpen");
								}
								if (i == 6)
								{
									List<double> list = (List<double>)obj;
									if (list.Count != 2)
									{
										jieRiFanBeiItemData.ExtArg1 = "1";
										jieRiFanBeiItemData.ExtArg2 = "1";
									}
									else
									{
										jieRiFanBeiItemData.ExtArg1 = list[0].ToString();
										jieRiFanBeiItemData.ExtArg2 = list[1].ToString();
									}
								}
								dictionary2[jieRiFanBeiItemData.Type] = jieRiFanBeiItemData;
							}
						}
					}
					SpecPriorityActivity specPriorityActivity = HuodongCachingMgr.GetSpecPriorityActivity();
					if (specPriorityActivity != null)
					{
						for (int j = 1; j < 4; j++)
						{
							if (specPriorityActivity.IsChouJiangOpen((SpecPActivityChouJiangType)j))
							{
								JieRiFanBeiItemData jieRiFanBeiItemData = new JieRiFanBeiItemData();
								jieRiFanBeiItemData.Type = j + 250;
								jieRiFanBeiItemData.IsOpen = 1;
								dictionary2[jieRiFanBeiItemData.Type] = jieRiFanBeiItemData;
							}
						}
						for (int j = 1; j < 14; j++)
						{
							SpecPActivityConfig specPActivityConfig;
							if (specPriorityActivity.IsMultiOpen((SpecPActivityBuffType)j, out specPActivityConfig))
							{
								JieRiFanBeiItemData jieRiFanBeiItemData = new JieRiFanBeiItemData();
								jieRiFanBeiItemData.Type = j + 200;
								jieRiFanBeiItemData.IsOpen = 1;
								jieRiFanBeiItemData.ExtArg1 = string.Format("{0}", specPriorityActivity.GetMult((SpecPActivityBuffType)j));
								dictionary2[jieRiFanBeiItemData.Type] = jieRiFanBeiItemData;
							}
						}
					}
					gameClient.sendCmd<Dictionary<int, JieRiFanBeiItemData>>(nID, dictionary2, false);
				}
				return TCPProcessCmdResults.RESULT_OK;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

