					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				string data2;
				if (69 != num2)
				{
					data2 = string.Format("{0}:{1}", -1, text);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				DanBiChongZhiActivity danBiChongZhiActivity = (DanBiChongZhiActivity)Global.GetActivity((ActivityTypes)num2);
				if (null == danBiChongZhiActivity)
				{
					data2 = string.Format("{0}:{1}", -1, text);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (!danBiChongZhiActivity.CanGiveAward())
				{
					data2 = string.Format("{0}:{1}", -2, text);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (!danBiChongZhiActivity.CheckCondition(gameClient, num3))
				{
					data2 = string.Format("{0}:{1}", -10007, text);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (!danBiChongZhiActivity.HasEnoughBagSpaceForAwardGoods(gameClient, num3))
				{
					data2 = string.Format("{0}:{1}", -3, text);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (69 == num2)
				{
					if (!danBiChongZhiActivity.CheckDanBiChongZhiCountOK(gameClient, num3))
					{
						data2 = string.Format("{0}:{1}", -5, text);
						tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
						return TCPProcessCmdResults.RESULT_DATA;
					}
				}
				string[] array2 = null;
				int dbserverExecuteActivityAwardCmdID = Global.GetDBServerExecuteActivityAwardCmdID((ActivityTypes)num2);
				string activityRequestCmdString = Global.GetActivityRequestCmdString((ActivityTypes)num2, gameClient, num3);
				if (dbserverExecuteActivityAwardCmdID <= 0 || string.IsNullOrEmpty(activityRequestCmdString))
				{
					data2 = string.Format("{0}:{1}", -4, text);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				Global.RequestToDBServer(tcpClientPool, pool, dbserverExecuteActivityAwardCmdID, activityRequestCmdString, out array2, gameClient.ServerId);
				if (array2 == null || array2.Length != 3)
				{
					data2 = string.Format("{0}:{1}", -5, text);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				int num4 = Global.SafeConvertToInt32(array2[0]);
				if (num4 <= 0)
				{
					data2 = string.Format("{0}:{1}", num4, text);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (!danBiChongZhiActivity.GiveAward(gameClient, Global.SafeConvertToInt32(array2[2])))
				{
					data2 = string.Format("{0}:{1}", -7, text);
					tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
					return TCPProcessCmdResults.RESULT_DATA;
				}
				if (gameClient._IconStateMgr.CheckJieRiActivity(gameClient, false))
				{
					gameClient._IconStateMgr.SendIconStateToClient(gameClient);
				}
				data2 = string.Format("{0}:{1}", num4, text);
				tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, "", false, false);
			}
			tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, "0", 30767);
			return TCPProcessCmdResults.RESULT_DATA;
		}

		private static TCPProcessCmdResults ProcessUpArtifact(TCPManager tcpMgr, TMSKSocket socket, TCPClientPool tcpClientPool, TCPOutPacketPool pool, int nID, byte[] data, int count, out TCPOutPacket tcpOutPacket)
		{
			tcpOutPacket = null;
			string text = null;
			try
			{
				text = new UTF8Encoding().GetString(data, 0, count);
			}
			catch (Exception)
			{
				LogManager.WriteLog(2, string.Format("解析指令字符串错误, CMD={0}, Client={1}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false)), null, true);
				return TCPProcessCmdResults.RESULT_FAILED;
			}
			try
			{
				string[] array = text.Split(new char[]
				{
					':'
				});
				if (array.Length != 3)
				{
					LogManager.WriteLog(2, string.Format("指令参数个数错误, CMD={0}, Client={1}, Recv={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), array.Length), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				int num = Convert.ToInt32(array[0]);
				int equipID = Convert.ToInt32(array[1]);
				bool isUseBind = Convert.ToInt32(array[2]) > 0;
				GameClient client = GameManager.ClientMgr.FindClient(socket);
				if (KuaFuManager.getInstance().ClientCmdCheckFaild(nID, client, ref num))
				{
					LogManager.WriteLog(2, string.Format("根据RoleID定位GameClient对象失败, CMD={0}, Client={1}, RoleID={2}", (TCPGameServerCmds)nID, Global.GetSocketRemoteEndPoint(socket, false), num), null, true);
					return TCPProcessCmdResults.RESULT_FAILED;
				}
				ArtifactResultData artifactResultData = ArtifactManager.UpArtifact(client, equipID, isUseBind);
				string data2 = string.Format("{0}:{1}:{2}", artifactResultData.State, artifactResultData.EquipDbID, artifactResultData.Bind);
				tcpOutPacket = TCPOutPacket.MakeTCPOutPacket(pool, data2, nID);
				return TCPProcessCmdResults.RESULT_DATA;
			}
			catch (Exception e)
			{
				DataHelper.WriteFormatExceptionLog(e, Global.GetDebugHelperInfo(socket), false, false);
			}
			return TCPProcessCmdResults.RESULT_FAILED;
		}

